// ── Données des articles ─────────────────────────────────────────────────────

const _articleData = {
    1: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Th\u00e9orie</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le MEDAF \u2014 Comprendre le prix du risque</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 6 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Lorsqu'on investit, on prend un risque. Il est donc naturel d'attendre une r\u00e9compense en \u00e9change. Mais combien exactement ? C'est pr\u00e9cis\u00e9ment la question \u00e0 laquelle r\u00e9pond le <strong style=\"color:var(--ink)\">Mod\u00e8le d'\u00c9valuation Des Actifs Financiers</strong> \u2014 le MEDAF, ou CAPM en anglais.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'id\u00e9e fondamentale</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le MEDAF, d\u00e9velopp\u00e9 dans les ann\u00e9es 1960 par William Sharpe (prix Nobel 1990), part d'une intuition simple : un investisseur rationnel ne prend pas de risque pour rien. Plus un actif est risqu\u00e9, plus il doit offrir un rendement \u00e9lev\u00e9 pour attirer des capitaux.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Mais tous les risques ne se valent pas. Certains peuvent \u00eatre \u00e9limin\u00e9s en diversifiant son portefeuille \u2014 c'est le <em>risque sp\u00e9cifique</em>. D'autres non : ils collent \u00e0 l'ensemble du march\u00e9 \u2014 c'est le <em>risque syst\u00e9matique</em>. Le march\u00e9 ne r\u00e9mun\u00e8re que ce second type de risque.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:24px;margin:28px 0\">\n<div style=\"font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted);margin-bottom:16px\">Illustration \u2014 La diversification r\u00e9duit le risque</div>\n<svg viewBox=\"0 0 600 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:100%;height:auto\">\n<defs><linearGradient id=\"gBlu2\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"0\"><stop offset=\"0%\" stop-color=\"#3466a0\" stop-opacity=\"0.15\"/><stop offset=\"100%\" stop-color=\"#3466a0\" stop-opacity=\"0.03\"/></linearGradient></defs>\n<line x1=\"60\" y1=\"20\" x2=\"60\" y2=\"170\" stroke=\"var(--border2)\" stroke-width=\"1.5\"/>\n<line x1=\"60\" y1=\"170\" x2=\"580\" y2=\"170\" stroke=\"var(--border2)\" stroke-width=\"1.5\"/>\n<text x=\"30\" y=\"100\" fill=\"var(--muted)\" font-size=\"10\" text-anchor=\"middle\" transform=\"rotate(-90,30,100)\" font-family=\"DM Sans,sans-serif\">Risque total</text>\n<text x=\"320\" y=\"192\" fill=\"var(--muted)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\">Nombre d'actifs</text>\n<path d=\"M70,40 Q120,42 180,70 Q260,100 360,130 Q440,148 560,155\" fill=\"none\" stroke=\"#1e3a5f\" stroke-width=\"2.5\" stroke-linecap=\"round\"/>\n<path d=\"M70,40 Q120,42 180,70 Q260,100 360,130 Q440,148 560,155 L560,155 L70,155 Z\" fill=\"url(#gBlu2)\"/>\n<line x1=\"70\" y1=\"155\" x2=\"560\" y2=\"155\" stroke=\"#c4820a\" stroke-width=\"1.8\" stroke-dasharray=\"6,4\"/>\n<text x=\"390\" y=\"90\" fill=\"#1e3a5f\" font-size=\"10\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Risque sp\u00e9cifique (diversifiable)</text>\n<text x=\"390\" y=\"163\" fill=\"#c4820a\" font-size=\"10\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Risque syst\u00e9matique</text>\n</svg>\n<p style=\"font-size:0.72rem;color:var(--muted);margin-top:10px;font-style:italic\">Plus on ajoute d'actifs non corr\u00e9l\u00e9s, plus le risque sp\u00e9cifique diminue. Il reste toujours un plancher : le risque de march\u00e9.</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La formule du MEDAF</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">E(R<sub>i</sub>) = R<sub>f</sub> + \u03b2<sub>i</sub> \u00d7 (E(R<sub>m</sub>) \u2212 R<sub>f</sub>)</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\"><strong>R<sub>f</sub></strong> taux sans risque \u00b7 <strong>\u03b2<sub>i</sub></strong> b\u00eata \u00b7 <strong>E(R<sub>m</sub>)\u2212R<sub>f</sub></strong> prime de risque de march\u00e9</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le rendement attendu d'un actif est la somme du taux sans risque et d'une prime proportionnelle \u00e0 son exposition au march\u00e9, mesur\u00e9e par le b\u00eata.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La droite de march\u00e9 des titres (SML)</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:24px;margin:20px 0\">\n<div style=\"font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted);margin-bottom:16px\">Security Market Line</div>\n<svg viewBox=\"0 0 600 240\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:100%;height:auto\">\n<line x1=\"60\" y1=\"20\" x2=\"60\" y2=\"200\" stroke=\"var(--border2)\" stroke-width=\"1.5\"/>\n<line x1=\"60\" y1=\"200\" x2=\"580\" y2=\"200\" stroke=\"var(--border2)\" stroke-width=\"1.5\"/>\n<text x=\"320\" y=\"220\" fill=\"var(--muted)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\">B\u00eata (\u03b2)</text>\n<line x1=\"60\" y1=\"175\" x2=\"560\" y2=\"40\" stroke=\"#1e3a5f\" stroke-width=\"2.5\"/>\n<circle cx=\"60\" cy=\"175\" r=\"5\" fill=\"#7a1f2e\"/>\n<text x=\"70\" y=\"171\" fill=\"#7a1f2e\" font-size=\"10\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Rf</text>\n<line x1=\"310\" y1=\"200\" x2=\"310\" y2=\"107\" stroke=\"var(--border2)\" stroke-width=\"1\" stroke-dasharray=\"4,3\"/>\n<circle cx=\"310\" cy=\"107\" r=\"6\" fill=\"#c4820a\"/>\n<text x=\"318\" y=\"103\" fill=\"#c4820a\" font-size=\"10\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">March\u00e9 \u03b2=1</text>\n<circle cx=\"200\" cy=\"115\" r=\"6\" fill=\"#1a5c52\"/>\n<text x=\"210\" y=\"111\" fill=\"#1a5c52\" font-size=\"10\" font-family=\"DM Sans,sans-serif\">Sous-\u00e9valu\u00e9</text>\n<circle cx=\"400\" cy=\"115\" r=\"6\" fill=\"#b03045\"/>\n<text x=\"410\" y=\"111\" fill=\"#b03045\" font-size=\"10\" font-family=\"DM Sans,sans-serif\">Sur\u00e9valu\u00e9</text>\n<text x=\"60\" y=\"213\" fill=\"var(--muted2)\" font-size=\"9\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\">0</text>\n<text x=\"560\" y=\"213\" fill=\"var(--muted2)\" font-size=\"9\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\">2</text>\n</svg>\n<p style=\"font-size:0.72rem;color:var(--muted);margin-top:10px;font-style:italic\">Les actifs au-dessus de la SML sont sous-\u00e9valu\u00e9s (opportunit\u00e9 d'achat), ceux en dessous sont sur\u00e9valu\u00e9s.</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Limites et port\u00e9e</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Le MEDAF repose sur des hypoth\u00e8ses fortes : march\u00e9s parfaits, investisseurs rationnels, horizon unique, distributions normales. En pratique, ces conditions ne sont jamais pleinement r\u00e9unies.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Malgr\u00e9 ses limites, il reste le cadre de r\u00e9f\u00e9rence universel pour comprendre le lien risque-rendement et v\u00e9rifier si un portefeuille est correctement r\u00e9mun\u00e9r\u00e9 pour le risque pris.</p>",
    2: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Mesure du risque</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le B\u00eata (\u03b2) \u2014 Mesurer la sensibilit\u00e9 au march\u00e9</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Si le MEDAF est la th\u00e9orie, le <strong style=\"color:var(--ink)\">b\u00eata (\u03b2)</strong> en est l'outil de mesure central. Il quantifie la sensibilit\u00e9 d'un actif aux mouvements du march\u00e9. C'est la boussole du risque syst\u00e9matique.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Que signifie le b\u00eata ?</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Le b\u00eata mesure l'amplification ou l'att\u00e9nuation des mouvements de march\u00e9. Un b\u00eata de 1.5 signifie que si le march\u00e9 monte de 10 %, l'actif tend \u00e0 monter de 15 %.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Interpr\u00e9tation du b\u00eata</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Valeur</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Profil</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Exemple</th></tr>\n<tr style=\"border-bottom:1px solid var(--surface2)\"><td style=\"padding:10px 20px;font-family:var(--font-serif);font-weight:700;color:#7a1f2e\">\u03b2 &lt; 0</td><td style=\"padding:10px 20px;color:var(--ink2)\">Contre-cyclique</td><td style=\"padding:10px 20px;color:var(--muted)\">Or, d\u00e9riv\u00e9s de couverture</td></tr>\n<tr style=\"border-bottom:1px solid var(--surface2)\"><td style=\"padding:10px 20px;font-family:var(--font-serif);font-weight:700;color:#1a5c52\">\u03b2 = 0</td><td style=\"padding:10px 20px;color:var(--ink2)\">Ind\u00e9pendant</td><td style=\"padding:10px 20px;color:var(--muted)\">Bons du Tr\u00e9sor court terme</td></tr>\n<tr style=\"border-bottom:1px solid var(--surface2)\"><td style=\"padding:10px 20px;font-family:var(--font-serif);font-weight:700;color:#8a5a00\">0 &lt; \u03b2 &lt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">D\u00e9fensif</td><td style=\"padding:10px 20px;color:var(--muted)\">Utilities, sant\u00e9, alimentation</td></tr>\n<tr style=\"border-bottom:1px solid var(--surface2)\"><td style=\"padding:10px 20px;font-family:var(--font-serif);font-weight:700;color:#1e3a5f\">\u03b2 = 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">Neutre (march\u00e9)</td><td style=\"padding:10px 20px;color:var(--muted)\">ETF S&amp;P 500</td></tr>\n<tr><td style=\"padding:10px 20px;font-family:var(--font-serif);font-weight:700;color:#b03045\">\u03b2 &gt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">Agressif</td><td style=\"padding:10px 20px;color:var(--muted)\">Tech, biotech, cryptos</td></tr>\n</table>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le calcul du b\u00eata</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">\u03b2<sub>i</sub> = Cov(R<sub>i</sub>, R<sub>m</sub>) / Var(R<sub>m</sub>)</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\"><strong>Cov</strong> : covariance actif/march\u00e9 \u00b7 <strong>Var</strong> : variance du march\u00e9</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">En pratique, on estime le b\u00eata visuellement par la <em>pente de la droite de r\u00e9gression</em> entre les rendements hebdomadaires de l'actif et ceux du march\u00e9.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:24px;margin:20px 0\">\n<div style=\"font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted);margin-bottom:16px\">Droite de r\u00e9gression \u2014 Estimation du b\u00eata</div>\n<svg viewBox=\"0 0 600 260\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:100%;height:auto\">\n<line x1=\"60\" y1=\"20\" x2=\"60\" y2=\"220\" stroke=\"var(--border2)\" stroke-width=\"1.5\"/>\n<line x1=\"60\" y1=\"220\" x2=\"580\" y2=\"220\" stroke=\"var(--border2)\" stroke-width=\"1.5\"/>\n<line x1=\"60\" y1=\"120\" x2=\"580\" y2=\"120\" stroke=\"var(--surface3)\" stroke-width=\"1\"/>\n<line x1=\"320\" y1=\"20\" x2=\"320\" y2=\"220\" stroke=\"var(--surface3)\" stroke-width=\"1\"/>\n<text x=\"30\" y=\"125\" fill=\"var(--muted)\" font-size=\"10\" text-anchor=\"middle\" transform=\"rotate(-90,30,125)\" font-family=\"DM Sans,sans-serif\">Rendement actif</text>\n<text x=\"320\" y=\"242\" fill=\"var(--muted)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\">Rendement march\u00e9</text>\n<circle cx=\"150\" cy=\"165\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"180\" cy=\"152\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"210\" cy=\"142\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"240\" cy=\"138\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"270\" cy=\"128\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"300\" cy=\"120\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"330\" cy=\"112\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"360\" cy=\"100\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"390\" cy=\"92\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"420\" cy=\"82\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"450\" cy=\"70\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"170\" cy=\"148\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"350\" cy=\"118\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"130\" cy=\"178\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<line x1=\"100\" y1=\"185\" x2=\"520\" y2=\"55\" stroke=\"#1a5c52\" stroke-width=\"2.5\" stroke-linecap=\"round\"/>\n<text x=\"480\" y=\"62\" fill=\"#1a5c52\" font-size=\"11\" font-family=\"DM Sans,sans-serif\" font-weight=\"700\">\u03b2 = 1.5</text>\n<text x=\"54\" y=\"124\" fill=\"var(--muted2)\" font-size=\"9\" text-anchor=\"end\" font-family=\"DM Sans,sans-serif\">0%</text>\n<text x=\"316\" y=\"233\" fill=\"var(--muted2)\" font-size=\"9\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\">0%</text>\n</svg>\n<p style=\"font-size:0.72rem;color:var(--muted);margin-top:10px;font-style:italic\">La pente de la droite de r\u00e9gression donne le b\u00eata. Ici \u03b2 \u2248 1.5 : l'actif amplifie les mouvements du march\u00e9 d'un facteur 1.5.</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le b\u00eata du portefeuille</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">L'avantage du b\u00eata : il est <strong>additif</strong>. Le b\u00eata d'un portefeuille est simplement la moyenne pond\u00e9r\u00e9e des b\u00eatas de ses composants.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Un gestionnaire cherchant \u00e0 d\u00e9corr\u00e9ler son portefeuille du march\u00e9 visera un b\u00eata faible. \u00c0 l'inverse, un g\u00e9rant convaincu d'une hausse prochaine surpond\u00e8rera des actifs \u00e0 fort b\u00eata pour b\u00e9n\u00e9ficier d'un effet amplificateur naturel.</p>",
    3: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Th\u00e9orie avanc\u00e9e</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">L'APT \u2014 Quand le risque vient de partout</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 7 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le MEDAF est \u00e9l\u00e9gant mais simpliste : il r\u00e9duit tout le risque syst\u00e9matique \u00e0 un seul facteur \u2014 le march\u00e9. L'<strong style=\"color:var(--ink)\">Arbitrage Pricing Theory</strong> (APT), propos\u00e9e par Stephen Ross en 1976, l\u00e8ve cette contrainte et reconna\u00eet que l'\u00e9conomie est multidimensionnelle.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Plusieurs sources de risque</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Une action p\u00e9troli\u00e8re est sensible au prix du baril, aux taux d'int\u00e9r\u00eat, \u00e0 la croissance mondiale et aux tensions g\u00e9opolitiques. Pourquoi n'exposer qu'un seul chiffre pour capturer tout cela ? L'APT reconna\u00eet chaque source avec son propre b\u00eata et sa propre prime.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:24px;margin:28px 0\">\n<div style=\"font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted);margin-bottom:20px\">Les facteurs macro\u00e9conomiques de l'APT</div>\n<svg viewBox=\"0 0 600 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:100%;height:auto\">\n<rect x=\"245\" y=\"80\" width=\"110\" height=\"40\" rx=\"8\" fill=\"#1e3a5f\" opacity=\"0.9\"/>\n<text x=\"300\" y=\"105\" fill=\"white\" font-size=\"12\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Rendement actif</text>\n<rect x=\"30\" y=\"20\" width=\"100\" height=\"34\" rx=\"6\" fill=\"var(--surface2)\" stroke=\"var(--border)\"/>\n<text x=\"80\" y=\"41\" fill=\"var(--ink2)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Taux d'int\u00e9r\u00eat</text>\n<line x1=\"130\" y1=\"37\" x2=\"245\" y2=\"92\" stroke=\"#c4820a\" stroke-width=\"1.5\" stroke-dasharray=\"5,3\"/>\n<text x=\"185\" y=\"58\" fill=\"#c4820a\" font-size=\"9\" font-family=\"DM Sans,sans-serif\">\u03b2\u2081</text>\n<rect x=\"30\" y=\"83\" width=\"100\" height=\"34\" rx=\"6\" fill=\"var(--surface2)\" stroke=\"var(--border)\"/>\n<text x=\"80\" y=\"104\" fill=\"var(--ink2)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Inflation</text>\n<line x1=\"130\" y1=\"100\" x2=\"245\" y2=\"100\" stroke=\"#1a5c52\" stroke-width=\"1.5\" stroke-dasharray=\"5,3\"/>\n<text x=\"185\" y=\"96\" fill=\"#1a5c52\" font-size=\"9\" font-family=\"DM Sans,sans-serif\">\u03b2\u2082</text>\n<rect x=\"30\" y=\"146\" width=\"100\" height=\"34\" rx=\"6\" fill=\"var(--surface2)\" stroke=\"var(--border)\"/>\n<text x=\"80\" y=\"167\" fill=\"var(--ink2)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Croissance PIB</text>\n<line x1=\"130\" y1=\"163\" x2=\"245\" y2=\"108\" stroke=\"#7a1f2e\" stroke-width=\"1.5\" stroke-dasharray=\"5,3\"/>\n<text x=\"185\" y=\"148\" fill=\"#7a1f2e\" font-size=\"9\" font-family=\"DM Sans,sans-serif\">\u03b2\u2083</text>\n<rect x=\"470\" y=\"20\" width=\"100\" height=\"34\" rx=\"6\" fill=\"var(--surface2)\" stroke=\"var(--border)\"/>\n<text x=\"520\" y=\"41\" fill=\"var(--ink2)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Prix p\u00e9trole</text>\n<line x1=\"470\" y1=\"37\" x2=\"355\" y2=\"92\" stroke=\"#8a5a00\" stroke-width=\"1.5\" stroke-dasharray=\"5,3\"/>\n<text x=\"415\" y=\"58\" fill=\"#8a5a00\" font-size=\"9\" font-family=\"DM Sans,sans-serif\">\u03b2\u2084</text>\n<rect x=\"470\" y=\"83\" width=\"100\" height=\"34\" rx=\"6\" fill=\"var(--surface2)\" stroke=\"var(--border)\"/>\n<text x=\"520\" y=\"104\" fill=\"var(--ink2)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">March\u00e9 (CAPM)</text>\n<line x1=\"470\" y1=\"100\" x2=\"355\" y2=\"100\" stroke=\"#3466a0\" stroke-width=\"1.5\" stroke-dasharray=\"5,3\"/>\n<text x=\"415\" y=\"96\" fill=\"#3466a0\" font-size=\"9\" font-family=\"DM Sans,sans-serif\">\u03b2\u2085</text>\n<rect x=\"470\" y=\"146\" width=\"100\" height=\"34\" rx=\"6\" fill=\"var(--surface2)\" stroke=\"var(--border)\"/>\n<text x=\"520\" y=\"167\" fill=\"var(--ink2)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Spread cr\u00e9dit</text>\n<line x1=\"470\" y1=\"163\" x2=\"355\" y2=\"108\" stroke=\"#1e3a5f\" stroke-width=\"1.5\" stroke-dasharray=\"5,3\"/>\n<text x=\"415\" y=\"148\" fill=\"#1e3a5f\" font-size=\"9\" font-family=\"DM Sans,sans-serif\">\u03b2\u2086</text>\n</svg>\n<p style=\"font-size:0.72rem;color:var(--muted);margin-top:12px;font-style:italic\">Chaque facteur macro\u00e9conomique contribue au rendement via son propre b\u00eata. L'APT est un MEDAF g\u00e9n\u00e9ralis\u00e9.</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'argument d'arbitrage</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Si deux actifs ont les m\u00eames expositions aux facteurs, ils doivent avoir le m\u00eame rendement attendu. Sinon, un arbitrage sans risque serait possible \u2014 ce qui, sur un march\u00e9 efficace, ne peut pas durer.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Cette logique est plus g\u00e9n\u00e9rale que celle du MEDAF : elle ne n\u00e9cessite pas que les investisseurs soient mean-variance optimaux, ni que les rendements soient normalement distribu\u00e9s.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">APT vs MEDAF</h2>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0\">\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:20px\">\n<div style=\"font-family:var(--font-serif);font-weight:700;color:var(--blue);font-size:1rem;margin-bottom:12px\">MEDAF</div>\n<ul style=\"list-style:none;padding:0;margin:0;font-size:0.85rem;color:var(--ink2);line-height:1.9\">\n<li style=\"padding:4px 0;border-bottom:1px solid var(--surface2)\">\u2726 1 seul facteur (march\u00e9)</li>\n<li style=\"padding:4px 0;border-bottom:1px solid var(--surface2)\">\u2726 Mod\u00e8le d'\u00e9quilibre g\u00e9n\u00e9ral</li>\n<li style=\"padding:4px 0;border-bottom:1px solid var(--surface2)\">\u2726 Simple et universel</li>\n<li style=\"padding:4px 0\">\u2726 Hypoth\u00e8ses fortes</li>\n</ul>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:20px\">\n<div style=\"font-family:var(--font-serif);font-weight:700;color:var(--teal);font-size:1rem;margin-bottom:12px\">APT</div>\n<ul style=\"list-style:none;padding:0;margin:0;font-size:0.85rem;color:var(--ink2);line-height:1.9\">\n<li style=\"padding:4px 0;border-bottom:1px solid var(--surface2)\">\u2726 K facteurs au choix</li>\n<li style=\"padding:4px 0;border-bottom:1px solid var(--surface2)\">\u2726 Argument d'arbitrage</li>\n<li style=\"padding:4px 0;border-bottom:1px solid var(--surface2)\">\u2726 Plus flexible et riche</li>\n<li style=\"padding:4px 0\">\u2726 Facteurs \u00e0 identifier</li>\n</ul>\n</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'APT dans la pratique</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">L'h\u00e9ritage direct de l'APT, c'est le mod\u00e8le de Fama-French (1993) : trois facteurs \u2014 le march\u00e9, la taille des entreprises (SMB) et leur valorisation (HML). Aujourd'hui, les mod\u00e8les \u00e0 5 ou 6 facteurs sont la norme en finance quantitative.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Les grands fonds institutionnels utilisent des mod\u00e8les APT calibr\u00e9s sur des dizaines de facteurs pour d\u00e9composer leur risque et construire des portefeuilles r\u00e9ellement diversifi\u00e9s \u2014 au sens factoriel du terme.</p>"
  };


// ── Articles supplémentaires (KPI de l'onglet actif) ─────────────────────────
Object.assign(_articleData, {
  4: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le P/E \u2014 Ce que vous payez vraiment pour chaque euro de profit</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Imaginez deux boulangeries \u00e0 vendre. La premi\u00e8re rapporte 10 000 \u20ac par an et se vend 100 000 \u20ac. La seconde rapporte le m\u00eame b\u00e9n\u00e9fice mais se vend 350 000 \u20ac. Laquelle est la plus ch\u00e8re ? La r\u00e9ponse semble \u00e9vidente \u2014 et pourtant, c'est exactement ce que mesure le ratio P/E en bourse. Cet indicateur, l'un des plus suivis au monde, vous dit combien le march\u00e9 est pr\u00eat \u00e0 payer pour chaque euro de b\u00e9n\u00e9fice g\u00e9n\u00e9r\u00e9 par une entreprise.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La formule</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">P/E = Prix de l'action \u00f7 B\u00e9n\u00e9fice Net par Action (BNA)</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : action \u00e0 50 \u20ac \u00b7 BNA de 2,50 \u20ac \u2192 P/E = 20x</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le r\u00e9sultat s'exprime en \"fois\" (ou \"x\"). Un P/E de 20 signifie que le march\u00e9 paie 20 \u20ac pour chaque euro de b\u00e9n\u00e9fice annuel. C'est aussi l'inverse du rendement implicite : un P/E de 20 \u00e9quivaut \u00e0 un rendement b\u00e9n\u00e9ficiaire de 5 %.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Spectre des valorisations par secteur</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:24px;margin:28px 0\">\n<div style=\"font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted);margin-bottom:16px\">P/E moyen par secteur</div>\n<svg viewBox=\"0 0 600 220\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:100%;height:auto\">\n<text x=\"10\" y=\"38\" font-size=\"11\" fill=\"var(--muted)\" font-family=\"sans-serif\">Value / Banques</text>\n<text x=\"10\" y=\"78\" font-size=\"11\" fill=\"var(--muted)\" font-family=\"sans-serif\">Utilities</text>\n<text x=\"10\" y=\"118\" font-size=\"11\" fill=\"var(--muted)\" font-family=\"sans-serif\">Consommation</text>\n<text x=\"10\" y=\"158\" font-size=\"11\" fill=\"var(--muted)\" font-family=\"sans-serif\">Sant\u00e9</text>\n<text x=\"10\" y=\"198\" font-size=\"11\" fill=\"var(--muted)\" font-family=\"sans-serif\">Technologie</text>\n<rect x=\"160\" y=\"20\" width=\"66\" height=\"22\" rx=\"4\" fill=\"var(--teal)\" opacity=\"0.85\"/><text x=\"232\" y=\"35\" font-size=\"11\" font-weight=\"700\" fill=\"var(--ink)\" font-family=\"sans-serif\">~10x</text>\n<rect x=\"160\" y=\"60\" width=\"100\" height=\"22\" rx=\"4\" fill=\"var(--teal)\" opacity=\"0.7\"/><text x=\"266\" y=\"75\" font-size=\"11\" font-weight=\"700\" fill=\"var(--ink)\" font-family=\"sans-serif\">~15x</text>\n<rect x=\"160\" y=\"100\" width=\"146\" height=\"22\" rx=\"4\" fill=\"var(--blue)\" opacity=\"0.7\"/><text x=\"312\" y=\"115\" font-size=\"11\" font-weight=\"700\" fill=\"var(--ink)\" font-family=\"sans-serif\">~22x</text>\n<rect x=\"160\" y=\"140\" width=\"186\" height=\"22\" rx=\"4\" fill=\"var(--blue)\" opacity=\"0.85\"/><text x=\"352\" y=\"155\" font-size=\"11\" font-weight=\"700\" fill=\"var(--ink)\" font-family=\"sans-serif\">~28x</text>\n<rect x=\"160\" y=\"180\" width=\"234\" height=\"22\" rx=\"4\" fill=\"var(--amber)\" opacity=\"0.85\"/><text x=\"400\" y=\"195\" font-size=\"11\" font-weight=\"700\" fill=\"var(--ink)\" font-family=\"sans-serif\">~35x</text>\n<line x1=\"160\" y1=\"210\" x2=\"560\" y2=\"210\" stroke=\"var(--border)\" stroke-width=\"1\"/>\n<text x=\"160\" y=\"220\" font-size=\"9\" fill=\"var(--muted)\" font-family=\"sans-serif\" text-anchor=\"middle\">0</text>\n<text x=\"294\" y=\"220\" font-size=\"9\" fill=\"var(--muted)\" font-family=\"sans-serif\" text-anchor=\"middle\">20</text>\n<text x=\"427\" y=\"220\" font-size=\"9\" fill=\"var(--muted)\" font-family=\"sans-serif\" text-anchor=\"middle\">40</text>\n<text x=\"560\" y=\"220\" font-size=\"9\" fill=\"var(--muted)\" font-family=\"sans-serif\" text-anchor=\"middle\">60</text>\n</svg>\n<p style=\"font-size:0.72rem;color:var(--muted);margin-top:10px;font-style:italic\">Moyennes historiques indicatives. Les P/E varient selon les cycles \u00e9conomiques et les taux d'int\u00e9r\u00eat.</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Grille d'interpr\u00e9tation</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Interpr\u00e9tation du P/E</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">P/E</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Signal</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Profil typique</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 10</td><td style=\"padding:10px 20px;color:var(--ink2)\">Potentiel value</td><td style=\"padding:10px 20px;color:var(--ink2)\">Cyclique en bas de cycle ou difficult\u00e9 structurelle</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--ink);font-weight:700\">10 \u2013 20</td><td style=\"padding:10px 20px;color:var(--ink2)\">Zone raisonnable</td><td style=\"padding:10px 20px;color:var(--ink2)\">Valorisation mod\u00e9r\u00e9e, secteurs matures ou d\u00e9fensifs</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--blue);font-weight:700\">20 \u2013 35</td><td style=\"padding:10px 20px;color:var(--ink2)\">Croissance anticip\u00e9e</td><td style=\"padding:10px 20px;color:var(--ink2)\">Le march\u00e9 price une croissance future solide</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">&gt; 35</td><td style=\"padding:10px 20px;color:var(--ink2)\">Forte prime</td><td style=\"padding:10px 20px;color:var(--ink2)\">Optimisme \u00e9lev\u00e9 \u2014 moindre marge d'erreur</td></tr>\n</table>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Limites \u00e0 conna\u00eetre</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\"><strong>BNA n\u00e9gatif</strong> : si une entreprise est d\u00e9ficitaire, le P/E n'est pas calculable. Se tourner alors vers P/S ou EV/EBITDA.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\"><strong>\u00c9l\u00e9ments exceptionnels</strong> : un b\u00e9n\u00e9fice gonfl\u00e9 par une cession ou r\u00e9duit par une d\u00e9pr\u00e9ciation fausse le ratio. Toujours regarder le b\u00e9n\u00e9fice r\u00e9current.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\"><strong>Sensibilit\u00e9 aux taux</strong> : quand les taux montent, les valorisations se compriment. Un P/E de 25 en environnement de taux \u00e0 0 % n'a pas la m\u00eame signification qu'\u00e0 5 %.</p>",
  5: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Price/Book \u2014 Ce que vaut vraiment l'entreprise si tout s'arr\u00eatait</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Supposez qu'une entreprise ferme ses portes aujourd'hui. Elle vend ses actifs, rembourse ses dettes. Ce qui reste appartient aux actionnaires : c'est la valeur comptable. Le ratio Price-to-Book (P/B) compare ce que le march\u00e9 paie \u00e0 cette valeur de liquidation th\u00e9orique.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La formule</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">P/B = Prix de l'action \u00f7 (Actifs \u2212 Dettes) par action</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Aussi \u00e9crit : Capitalisation boursi\u00e8re \u00f7 Capitaux propres totaux</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Un P/B de 1 signifie que le march\u00e9 valorise l'entreprise exactement \u00e0 la valeur de ses actifs nets. Un P/B inf\u00e9rieur \u00e0 1 est th\u00e9oriquement intrigant : le march\u00e9 valorise l'entreprise moins cher que sa valeur de liquidation.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Grille d'interpr\u00e9tation du P/B</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">P/B</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Signal</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">D\u00e9cote sur actifs \u2014 opportunit\u00e9 ou signal de difficult\u00e9s</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;font-weight:700\">1 \u2013 2</td><td style=\"padding:10px 20px;color:var(--ink2)\">Raisonnable \u2014 typique banques, industries matures</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--blue);font-weight:700\">2 \u2013 5</td><td style=\"padding:10px 20px;color:var(--ink2)\">Prime de qualit\u00e9 \u2014 marque forte, avantage concurrentiel</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">&gt; 5</td><td style=\"padding:10px 20px;color:var(--ink2)\">Forte intangibilit\u00e9 \u2014 logiciels, brevets, marques non comptabilis\u00e9es</td></tr>\n</table>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Quand le P/B est-il vraiment utile ?</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Le P/B brille pour les secteurs o\u00f9 les actifs tangibles sont centraux : <strong>banques, assurances, fonci\u00e8res, industries lourdes</strong>. En revanche, il perd de sa pertinence pour les entreprises dont la valeur r\u00e9side dans l'immat\u00e9riel \u2014 logiciels, marques, r\u00e9seaux. Leur P/B sera structurellement \u00e9lev\u00e9, sans que ce soit anormal.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Il existe une relation logique entre P/B et ROE : une entreprise qui g\u00e9n\u00e8re 20 % de rentabilit\u00e9 sur ses fonds propres m\u00e9rite naturellement un P/B plus \u00e9lev\u00e9 qu'une entreprise \u00e0 5 %. Toujours croiser les deux.</p>",
  6: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Price/Sales \u2014 Valoriser m\u00eame sans profit</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Une startup qui cro\u00eet \u00e0 80 % par an mais perd de l'argent \u2014 comment la valoriser ? Le P/E est inutilisable. C'est ici qu'intervient le <strong>Price-to-Sales</strong>, qui ram\u00e8ne la valorisation au chiffre d'affaires. Il offre un terrain de comparaison universel, m\u00eame pour des entreprises sans profit.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">P/S = Capitalisation boursi\u00e8re \u00f7 Chiffre d'affaires annuel</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : cap. boursi\u00e8re de 500 M\u20ac \u00b7 CA de 100 M\u20ac \u2192 P/S = 5x</div>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Niveaux de P/S selon le profil</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">P/S</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Profil typique</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">Distribution, industrie lourde \u2014 marges faibles structurelles</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;font-weight:700\">1 \u2013 3</td><td style=\"padding:10px 20px;color:var(--ink2)\">Zone standard \u2014 entreprises matures avec marges raisonnables</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--blue);font-weight:700\">3 \u2013 10</td><td style=\"padding:10px 20px;color:var(--ink2)\">SaaS, tech, biotech avec croissance visible</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">&gt; 10</td><td style=\"padding:10px 20px;color:var(--ink2)\">Hypercroissance \u2014 tr\u00e8s sensible aux d\u00e9ceptions</td></tr>\n</table>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'astuce du P/E normalis\u00e9</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.3rem;color:var(--ink)\">P/E normalis\u00e9 = P/S \u00f7 Marge nette cible</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : P/S de 8x \u00b7 marge nette cible de 20% \u2192 P/E implicite = 40x</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Cette approche permet de tester la coh\u00e9rence d'une valorisation. Si le P/E implicite est de 100x pour une marge cible de 8 %, la valorisation est difficile \u00e0 d\u00e9fendre. Le P/S doit toujours \u00eatre accompagn\u00e9 d'une analyse des marges.</p>",
  7: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Price/FCF \u2014 Mesurer la valeur avec le vrai cash</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le ratio Price/FCF est consid\u00e9r\u00e9 par de nombreux investisseurs professionnels comme le multiple de valorisation le plus honn\u00eate. L\u00e0 o\u00f9 le b\u00e9n\u00e9fice net peut \u00eatre fa\u00e7onn\u00e9 par des choix comptables, le free cash flow est du cash r\u00e9el \u2014 celui qui entre dans la caisse apr\u00e8s que l'entreprise a pay\u00e9 ses investissements.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">P/FCF = Capitalisation boursi\u00e8re / Free Cash Flow annuel</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">FCF = Flux op\u00e9rationnel \u2212 Capex (d\u00e9penses d'investissement)</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Pourquoi plus fiable que le P/E</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le b\u00e9n\u00e9fice net peut \u00eatre artificiellement gonfl\u00e9 par des choix d'amortissement, des provisions ou des cessions d'actifs. Le FCF est beaucoup plus difficile \u00e0 manipuler : soit l'argent est dans la caisse, soit il n'y est pas.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n<div style=\"font-size:0.72rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;color:var(--amber);margin-bottom:8px\">Exemple concret</div>\n<p style=\"font-size:0.92rem;line-height:1.65;color:var(--ink2);margin:0\">Entreprise avec un b\u00e9n\u00e9fice net de 100 M\u20ac mais des capex de maintenance de 80 M\u20ac. Son FCF r\u00e9el est de 20 M\u20ac. Si le march\u00e9 la valorise \u00e0 1 Md\u20ac, le P/E apparent est de 10\u00d7 (attractif) mais le P/FCF est de 50\u00d7 (tr\u00e8s cher).</p>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Rep\u00e8res P/FCF</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">P/FCF</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Signal</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 15</td><td style=\"padding:10px 20px;color:var(--ink2)\">Potentiellement attractif</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">15 \u2013 25</td><td style=\"padding:10px 20px;color:var(--ink2)\">Valorisation correcte</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&gt; 25</td><td style=\"padding:10px 20px;color:var(--ink2)\">Prime \u00e9lev\u00e9e \u2014 justifi\u00e9 uniquement par forte croissance</td></tr>\n</table>\n</div>",
  8: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le PEG Ratio \u2014 Le P/E ajust\u00e9 \u00e0 la croissance</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Un P/E de 30 est-il forc\u00e9ment plus cher qu'un P/E de 15 ? Pas n\u00e9cessairement. C'est l'intuition fondatrice du PEG Ratio, popularis\u00e9 par Peter Lynch. Le PEG int\u00e8gre la croissance des b\u00e9n\u00e9fices dans l'\u00e9quation de valorisation \u2014 et renverse parfois compl\u00e8tement le jugement.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">PEG = P/E \u00f7 Taux de croissance annuel des b\u00e9n\u00e9fices (%)</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : P/E de 30 \u00f7 croissance de 30 % = PEG de 1,0</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La r\u00e8gle empirique de Peter Lynch</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Peter Lynch utilisait une r\u00e8gle simple : <strong>une action est correctement valoris\u00e9e quand son PEG est \u00e9gal \u00e0 1</strong>. En dessous de 1, potentiellement sous-\u00e9valu\u00e9e. Au-dessus de 2, la croissance attendue est d\u00e9j\u00e0 largement int\u00e9gr\u00e9e dans le prix.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Rep\u00e8res PEG</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">PEG</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Signal</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">Potentiellement sous-\u00e9valu\u00e9 \u2014 croissance non enti\u00e8rement pric\u00e9e</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">1 \u2013 2</td><td style=\"padding:10px 20px;color:var(--ink2)\">Valorisation juste \u2014 coh\u00e9rente avec les perspectives</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&gt; 2</td><td style=\"padding:10px 20px;color:var(--ink2)\">Cher \u2014 croissance future d\u00e9j\u00e0 largement int\u00e9gr\u00e9e</td></tr>\n</table>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Le PEG n'est aussi bon que l'estimation de croissance qu'on y introduit. Utilisez de pr\u00e9f\u00e9rence la croissance historique sur 5 ans, pas les estimations prospectives souvent optimistes des analystes.</p>",
  9: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">EV/Revenue \u2014 La valeur d'entreprise face au chiffre d'affaires</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">L'EV/Revenue mesure combien l'ensemble des apporteurs de capitaux (actionnaires <em>et</em> cr\u00e9anciers) paient pour chaque euro de chiffre d'affaires. Contrairement au P/S, il prend en compte la structure financi\u00e8re de l'entreprise.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">EV = Capitalisation + Dette nette \u2212 Tr\u00e9sorerie</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">EV/Rev = (Capitalisation + Dettes nettes) / CA \u2014 ind\u00e9pendant de la structure du capital</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'avantage d\u00e9cisif sur le P/S</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Deux soci\u00e9t\u00e9s avec le m\u00eame CA et la m\u00eame capitalisation auront un P/S identique, m\u00eame si l'une porte 500 M\u20ac de dette nette et l'autre a 500 M\u20ac de tr\u00e9sorerie. L'EV/Revenue, lui, int\u00e8gre cette r\u00e9alit\u00e9.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Rep\u00e8res EV/Revenue</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">EV/Rev</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Contexte</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 2\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">Industrie, value \u2014 valorisation modeste</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">2\u00d7 \u2013 8\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">Tech \u00e9tablie, SaaS rentable</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&gt; 10\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">SaaS hypercroissance \u2014 justifi\u00e9 seulement par croissance &gt; 40 %</td></tr>\n</table>\n</div>",
  10: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Fondamentaux</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Capitalisation Boursi\u00e8re \u2014 Ce que le march\u00e9 pense de votre entreprise</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La <strong>capitalisation boursi\u00e8re</strong> est ce que l'ensemble des investisseurs accepte collectivement de payer pour poss\u00e9der 100 % de l'entreprise \u00e0 l'instant T. Ce n'est pas la valeur comptable, ni la valeur des actifs.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">Capitalisation = Prix de l'action \u00d7 Nombre d'actions en circulation</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : action \u00e0 150 \u20ac \u00d7 500 millions d'actions = capitalisation de 75 milliards \u20ac</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le spectre des tailles de march\u00e9</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Cat\u00e9gories par capitalisation</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Cat\u00e9gorie</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Seuil</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Profil</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--ink2)\">Nano/Micro cap</td><td style=\"padding:10px 20px;color:var(--ink2)\">&lt; 300 M\u20ac</td><td style=\"padding:10px 20px;color:var(--ink2)\">Forte volatilit\u00e9, liquidit\u00e9 faible, potentiel \u00e9lev\u00e9</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--ink2)\">Small cap</td><td style=\"padding:10px 20px;color:var(--ink2)\">300 M \u2013 2 Mrd</td><td style=\"padding:10px 20px;color:var(--ink2)\">PME innovantes, croissance visible</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--ink2)\">Mid cap</td><td style=\"padding:10px 20px;color:var(--ink2)\">2 \u2013 10 Mrd</td><td style=\"padding:10px 20px;color:var(--ink2)\">Leaders sectoriels, profil \u00e9quilibr\u00e9</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--ink2)\">Large cap</td><td style=\"padding:10px 20px;color:var(--ink2)\">10 \u2013 200 Mrd</td><td style=\"padding:10px 20px;color:var(--ink2)\">CAC 40, stabilit\u00e9, dividendes fr\u00e9quents</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--ink2)\">Mega cap</td><td style=\"padding:10px 20px;color:var(--ink2)\">&gt; 200 Mrd</td><td style=\"padding:10px 20px;color:var(--ink2)\">Apple, LVMH \u2014 liquidit\u00e9 maximale</td></tr>\n</table>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Capitalisation vs Valeur d'Entreprise</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">La capitalisation ignore la structure financi\u00e8re. La <strong>Valeur d'Entreprise (EV)</strong> = Capitalisation + Dette financi\u00e8re nette \u2212 Tr\u00e9sorerie est plus compl\u00e8te pour comparer des soci\u00e9t\u00e9s aux bilans diff\u00e9rents.</p>",
  11: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le BNA \u2014 Le b\u00e9n\u00e9fice ramen\u00e9 \u00e0 l'\u00e9chelle de chaque action</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Une entreprise peut afficher 2 milliards de b\u00e9n\u00e9fice et \u00eatre jug\u00e9e d\u00e9cevante. Une autre peut publier 400 millions et faire bondir son cours. La cl\u00e9 : le nombre d'actions. Le <strong>B\u00e9n\u00e9fice Net par Action (BNA)</strong> neutralise cette variable pour comparer les r\u00e9sultats sur un pied d'\u00e9galit\u00e9.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">BNA = B\u00e9n\u00e9fice net / Nombre d'actions en circulation</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : 800 M\u20ac \u00f7 400 M actions = BNA de 2,00 \u20ac</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">BNA basique vs BNA dilu\u00e9</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le <strong>BNA dilu\u00e9</strong> tient compte de toutes les actions potentiellement cr\u00e9\u00e9es si les stock-options et obligations convertibles \u00e9taient exerc\u00e9es. Il est toujours inf\u00e9rieur ou \u00e9gal au BNA basique. Dans les entreprises tech \u00e0 forte culture de r\u00e9mun\u00e9ration en actions, la dilution peut d\u00e9passer 5 \u00e0 10 % par an.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:16px 22px;margin:20px 0\">\n<p style=\"font-size:0.88rem;line-height:1.7;color:var(--ink2);margin:0\"><strong>Exemple :</strong> 500 M\u20ac \u00b7 200 M actions (basique) \u2192 BNA = 2,50 \u20ac \u00b7 Avec 40 M options : BNA dilu\u00e9 = 500 \u00f7 240 = 2,08 \u20ac \u2014 \u00e9cart de 17 %.</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La croissance du BNA : moteur num\u00e9ro un des cours</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Sur le long terme, la croissance du BNA explique l'essentiel de la performance boursi\u00e8re. Quand une entreprise \"bat le consensus\" (BNA sup\u00e9rieur aux attentes), le cours r\u00e9agit positivement \u2014 m\u00eame si le BNA est en baisse absolue par rapport \u00e0 l'an pass\u00e9.</p>",
  12: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Flux de tr\u00e9sorerie</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Free Cash Flow \u2014 Le cash qui reste vraiment dans les mains de l'entreprise</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le b\u00e9n\u00e9fice net est une construction comptable. Le cash, lui, est r\u00e9el. Une entreprise peut afficher des b\u00e9n\u00e9fices en croissance pendant des ann\u00e9es tout en \u00e9tant perp\u00e9tuellement \u00e0 court de liquidit\u00e9s. C'est pour trancher cette ambigu\u00eft\u00e9 que les professionnels utilisent le <strong>Free Cash Flow</strong>.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">FCF = Flux de tr\u00e9sorerie op\u00e9rationnel \u2212 Capex</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Capex = d\u00e9penses d'investissement (machines, \u00e9quipements, immobilisations)</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Pourquoi les amortissements sont \"rajout\u00e9s\"</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Une machine achet\u00e9e 1 M\u20ac est amortie sur 10 ans : 100 k\u20ac de charge annuelle. Mais le cash a quitt\u00e9 l'entreprise lors de l'achat. L'amortissement est une charge <strong>non d\u00e9caiss\u00e9e</strong> \u2014 on la rajoute au r\u00e9sultat net pour retrouver le cash r\u00e9el.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le FCF : le nerf de la guerre</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Une fois le FCF calcul\u00e9, la direction peut l'allouer de quatre fa\u00e7ons :</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:20px 0\">\n<div style=\"background:var(--surface2);border-radius:8px;padding:14px 16px\"><div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;color:var(--teal);margin-bottom:6px\">Dividendes</div><p style=\"font-size:0.82rem;line-height:1.6;color:var(--ink2);margin:0\">Redistribution directe aux actionnaires.</p></div>\n<div style=\"background:var(--surface2);border-radius:8px;padding:14px 16px\"><div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;color:var(--blue);margin-bottom:6px\">Rachats d'actions</div><p style=\"font-size:0.82rem;line-height:1.6;color:var(--ink2);margin:0\">R\u00e9duit les actions, augmente m\u00e9caniquement le BNA.</p></div>\n<div style=\"background:var(--surface2);border-radius:8px;padding:14px 16px\"><div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;color:var(--amber);margin-bottom:6px\">Remboursement dette</div><p style=\"font-size:0.82rem;line-height:1.6;color:var(--ink2);margin:0\">R\u00e9duit le levier et les charges d'int\u00e9r\u00eats.</p></div>\n<div style=\"background:var(--surface2);border-radius:8px;padding:14px 16px\"><div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;color:var(--rose);margin-bottom:6px\">Acquisitions</div><p style=\"font-size:0.82rem;line-height:1.6;color:var(--ink2);margin:0\">La plus cr\u00e9atrice de valeur \u2014 si bien ex\u00e9cut\u00e9e.</p></div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\"><strong>FCF Yield</strong> = FCF / Capitalisation : si un titre affiche 8 % de FCF Yield vs un taux obligataire \u00e0 4 %, il g\u00e9n\u00e8re deux fois plus de \"rendement cash\" \u2014 avec plus de risque, certes.</p>",
  13: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Marge Op\u00e9rationnelle \u2014 L'efficacit\u00e9 brute du c\u0153ur de m\u00e9tier</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La <strong>marge op\u00e9rationnelle</strong> mesure la capacit\u00e9 d'une entreprise \u00e0 d\u00e9gager un b\u00e9n\u00e9fice \u00e0 partir de son seul c\u0153ur de m\u00e9tier, avant de payer ses cr\u00e9anciers et l'\u00c9tat. C'est l'outil id\u00e9al pour comparer des entreprises ind\u00e9pendamment de leur niveau d'endettement.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">Marge op\u00e9rationnelle = EBIT / Chiffre d'affaires \u00d7 100</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">EBIT = Earnings Before Interest and Taxes (r\u00e9sultat avant int\u00e9r\u00eats et imp\u00f4ts)</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Benchmarks sectoriels</h2>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n<div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Logiciel / SaaS</div>\n<div style=\"font-family:var(--font-serif);font-size:1.6rem;font-weight:700;color:var(--blue)\">25\u201340 %</div>\n<div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Co\u00fbts marginaux faibles, fort effet d'\u00e9chelle</div>\n</div>\n<div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Industrie</div>\n<div style=\"font-family:var(--font-serif);font-size:1.6rem;font-weight:700;color:var(--teal)\">8\u201315 %</div>\n<div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Co\u00fbts fixes \u00e9lev\u00e9s, investissements lourds</div>\n</div>\n<div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Distribution</div>\n<div style=\"font-family:var(--font-serif);font-size:1.6rem;font-weight:700;color:var(--amber)\">2\u20135 %</div>\n<div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Volumes \u00e9normes, marges unitaires compress\u00e9es</div>\n</div>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n<p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\"><strong>\u00c0 retenir :</strong> La marge op\u00e9rationnelle est neutre vis-\u00e0-vis de la structure financi\u00e8re. Deux entreprises identiques, l'une tr\u00e8s endett\u00e9e et l'autre sans dettes, afficheront la m\u00eame marge op\u00e9rationnelle si leur exploitation est aussi efficace.</p>\n</div>",
  14: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Marge Nette \u2014 Ce qui reste vraiment pour les actionnaires</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La <strong>marge nette</strong> r\u00e9v\u00e8le ce qui appartient r\u00e9ellement aux actionnaires une fois que l'entreprise a tout r\u00e9gl\u00e9 \u2014 fournisseurs, salari\u00e9s, banquiers et fisc. C'est le dernier centime du compte de r\u00e9sultat.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">Marge nette = B\u00e9n\u00e9fice net / Chiffre d'affaires \u00d7 100</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Apr\u00e8s int\u00e9r\u00eats sur la dette et imp\u00f4t sur les soci\u00e9t\u00e9s</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'\u00e9cart r\u00e9v\u00e9lateur entre marge op\u00e9rationnelle et marge nette</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Plus l'\u00e9cart entre ces deux marges est grand, plus l'entreprise porte un fardeau de dettes ou b\u00e9n\u00e9ficie d'un environnement fiscal particulier. Si la marge op\u00e9rationnelle est de 15 % et la marge nette de 9 %, les 6 points restants sont absorb\u00e9s par les int\u00e9r\u00eats et l'imp\u00f4t.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0\">\n<div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">Forte marge nette</div>\n<p style=\"font-size:0.88rem;line-height:1.7;color:var(--ink2)\"><strong>Logiciels / SaaS</strong> \u2014 15\u201330 %<br><strong>Luxe</strong> \u2014 10\u201325 %<br><strong>Pharmacie</strong> \u2014 15\u201325 %</p>\n</div>\n<div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:10px\">Faible marge nette</div>\n<p style=\"font-size:0.88rem;line-height:1.7;color:var(--ink2)\"><strong>Grande distribution</strong> \u2014 1\u20133 %<br><strong>Transport a\u00e9rien</strong> \u2014 1\u20135 %<br><strong>Agroalimentaire</strong> \u2014 2\u20136 %</p>\n</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">La marge nette utilis\u00e9e seule peut induire en erreur : une faible marge nette peut venir d'une dette excessive, pas d'une mauvaise exploitation. Toujours la croiser avec la marge op\u00e9rationnelle.</p>",
  15: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le ROE \u2014 Ce que l'entreprise rapporte sur chaque euro des actionnaires</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le <strong>ROE</strong> (Return On Equity) mesure le taux de rendement g\u00e9n\u00e9r\u00e9 par l'entreprise sur les capitaux appartenant aux actionnaires. C'est l'un des indicateurs favoris de Warren Buffett pour identifier les entreprises \u00e0 avantage concurrentiel durable.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">ROE = B\u00e9n\u00e9fice net / Capitaux propres \u00d7 100</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Un ROE de 20 % signifie que pour chaque euro des actionnaires, l'entreprise g\u00e9n\u00e8re 0,20 \u20ac de profit annuel</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La d\u00e9composition DuPont</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.2rem;color:var(--ink);line-height:1.8\">ROE = <span style=\"color:var(--teal)\">Marge nette</span> \u00d7 <span style=\"color:var(--blue)\">Rotation des actifs</span> \u00d7 <span style=\"color:var(--rose)\">Levier financier</span></div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">(B\u00e9n\u00e9fice/CA) \u00d7 (CA/Actif total) \u00d7 (Actif total/Capitaux propres)</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Cette d\u00e9composition r\u00e9v\u00e8le l'<em>origine</em> du ROE : vient-il d'une forte rentabilit\u00e9 commerciale, d'une utilisation efficace des actifs, ou d'un levier financier \u00e9lev\u00e9 ? Trois sources tr\u00e8s diff\u00e9rentes de performance.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les limites : quand le ROE ment</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\"><strong>La dette</strong> \u2014 En s'endettant massivement, l'entreprise r\u00e9duit ses capitaux propres au d\u00e9nominateur. Le m\u00eame b\u00e9n\u00e9fice net donne un ROE plus \u00e9lev\u00e9 \u2014 mais c'est un ROE fragile.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\"><strong>Les rachats d'actions</strong> \u2014 Ils r\u00e9duisent comptablement les capitaux propres. Apple, Microsoft ou Visa affichent des ROE spectaculaires (100 %+) gr\u00e2ce \u00e0 leurs rachats massifs. Toujours compl\u00e9ter avec le ROA (Return on Assets) qui neutralise l'effet de levier.</p>",
  16: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Dividendes</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Rendement du Dividende \u2014 Le taux d'int\u00e9r\u00eat naturel de l'action</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le <strong>rendement du dividende</strong> mesure le rapport entre le dividende annuel vers\u00e9 et le prix actuel de l'action. C'est le \"taux d'int\u00e9r\u00eat naturel\" de l'actif : plus le cours monte, plus le rendement baisse \u2014 et inversement.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">Rendement = (Dividende annuel / Prix de l'action) \u00d7 100</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : dividende de 2 \u20ac \u00b7 cours de 50 \u20ac \u2192 rendement de 4 %</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le pi\u00e8ge du rendement \u00e9lev\u00e9</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Un rendement de 10 % ou 15 % semble extraordinaire. Mais c'est souvent un signal d'alarme \u2014 le ph\u00e9nom\u00e8ne s'appelle le <strong>dividend yield trap</strong>. Le march\u00e9 a fait chuter le cours car il anticipe une r\u00e9duction du dividende. L'investisseur touche un ou deux versements g\u00e9n\u00e9reux, puis le dividende est coup\u00e9.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:16px 22px;margin:20px 0\">\n<div style=\"font-size:0.7rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:6px\">Signaux d'alerte</div>\n<ul style=\"font-size:0.88rem;line-height:1.8;color:var(--ink2);padding-left:18px\">\n<li>Rendement nettement sup\u00e9rieur \u00e0 la moyenne sectorielle</li>\n<li>Payout ratio sup\u00e9rieur \u00e0 80\u201390 %</li>\n<li>Endettement en hausse, flux de tr\u00e9sorerie en baisse</li>\n<li>Cours en chute de plus de 30 % sur 12 mois</li>\n</ul>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les Dividend Aristocrats</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Certaines entreprises augmentent leur dividende chaque ann\u00e9e depuis au moins 25 ans cons\u00e9cutifs. Ce club tr\u00e8s s\u00e9lect (Johnson &amp; Johnson, Procter &amp; Gamble, Coca-Cola) signale une solidit\u00e9 fondamentale exceptionnelle. Un rendement mod\u00e9r\u00e9 mais croissant vaut souvent mieux qu'un rendement \u00e9lev\u00e9 et fragile.</p>",
  17: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Dividendes</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Payout Ratio \u2014 Quelle part des b\u00e9n\u00e9fices part en dividendes ?</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le <strong>payout ratio</strong> mesure la part des b\u00e9n\u00e9fices redistribu\u00e9e aux actionnaires. Trop bas, l'entreprise th\u00e9saurise sans partager. Trop haut, elle distribue plus qu'elle ne peut se permettre. C'est une radiographie de la g\u00e9n\u00e9rosit\u00e9 <em>et</em> de la prudence d'une direction.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">Payout = (Dividende par action / BNA) \u00d7 100</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">FCF Payout = Dividendes vers\u00e9s / Free Cash Flow \u2014 plus fiable car bas\u00e9 sur du cash r\u00e9el</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les quatre zones</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"background:var(--surface2);border-bottom:1px solid var(--border)\"><th style=\"padding:10px 16px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Payout</th><th style=\"padding:10px 16px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Interpr\u00e9tation</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--teal);font-weight:700\">0 \u2013 40 %</td><td style=\"padding:10px 16px;color:var(--ink2)\">R\u00e9investissement prioritaire \u2014 dividende tr\u00e8s s\u00fbr avec marge de progression</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--blue);font-weight:700\">40 \u2013 70 %</td><td style=\"padding:10px 16px;color:var(--ink2)\">Zone id\u00e9ale \u2014 partage g\u00e9n\u00e9reux tout en conservant assez pour se d\u00e9velopper</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--amber);font-weight:700\">70 \u2013 100 %</td><td style=\"padding:10px 16px;color:var(--ink2)\">Vigilance \u2014 viable si r\u00e9sultats stables, peu de marge en cas de contraction</td></tr>\n<tr><td style=\"padding:10px 16px;color:var(--rose);font-weight:700\">&gt; 100 %</td><td style=\"padding:10px 16px;color:var(--ink2)\">Danger \u2014 l'entreprise finance son dividende par la dette ou ses r\u00e9serves</td></tr>\n</table>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:16px 22px;margin:20px 0\">\n<p style=\"font-size:0.88rem;line-height:1.75;color:var(--ink2);margin:0\"><strong>Exception :</strong> Les REIT (fonci\u00e8res cot\u00e9es) sont l\u00e9galement tenues de distribuer plus de 90 % de leurs revenus. Un payout \u00e9lev\u00e9 y est structurel et normal \u2014 pas un signal d'alarme.</p>\n</div>",
  18: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Actions</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Les Actions en Circulation \u2014 Dilution, rachats et ce qu'ils r\u00e9v\u00e8lent</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le nombre d'actions en circulation \u00e9volue dans le temps : il augmente quand l'entreprise \u00e9met de nouvelles actions (dilution), il diminue quand elle rach\u00e8te ses propres titres (buybacks). Cette \u00e9volution est l'un des signaux les plus sous-estim\u00e9s en analyse boursi\u00e8re.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'impact sur le BNA</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">\u00c0 r\u00e9sultat constant, si le nombre d'actions diminue, le BNA augmente m\u00e9caniquement. Apple a rachet\u00e9 pour plus de 600 Mrd$ de ses propres actions depuis 2012, r\u00e9duisant son flottant de plus de 40 %. Ce programme a \u00e9t\u00e9 l'un des moteurs de la progression du BNA bien au-del\u00e0 de la seule croissance des ventes.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les rachats comme signal de confiance</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Quand une direction rach\u00e8te massivement ses propres actions, elle envoie un message implicite : <strong>\"nous pensons que notre action est sous-\u00e9valu\u00e9e\"</strong>. Personne ne conna\u00eet mieux l'entreprise que ses dirigeants.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"background:var(--surface2);border-bottom:1px solid var(--border)\"><th style=\"padding:10px 16px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">\u00c9volution</th><th style=\"padding:10px 16px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Signal</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--ink2)\">Baisse r\u00e9guli\u00e8re (\u22122 \u00e0 \u22125 %/an)</td><td style=\"padding:10px 16px;color:var(--teal);font-weight:700\">Bullish \u2014 rachats actifs</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--ink2)\">Stabilit\u00e9 (\u00b11 %/an)</td><td style=\"padding:10px 16px;color:var(--muted);font-weight:700\">Neutre</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--ink2)\">Hausse mod\u00e9r\u00e9e (+1 \u00e0 +3 %/an)</td><td style=\"padding:10px 16px;color:var(--amber);font-weight:700\">Attention \u2014 stock-options exerc\u00e9es</td></tr>\n<tr><td style=\"padding:10px 16px;color:var(--ink2)\">Hausse forte (&gt;+5 %/an)</td><td style=\"padding:10px 16px;color:var(--rose);font-weight:700\">Bearish \u2014 augmentation de capital ou acquisition dilutive</td></tr>\n</table>\n</div>",
  19: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Sant\u00e9 financi\u00e8re</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Dette / Capitaux Propres \u2014 Mesurer l'\u00e9quilibre dettes / fonds propres</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le ratio <strong>D/E (Debt-to-Equity)</strong> mesure l'\u00e9quilibre entre les deux sources de financement d'une entreprise : la dette (ce qu'elle doit) et les capitaux propres (ce qu'elle poss\u00e8de en propre). C'est le premier indicateur \u00e0 consulter pour \u00e9valuer la solidit\u00e9 financi\u00e8re.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">D/E = Dettes totales / Capitaux propres</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Un D/E de 1,5 signifie que pour chaque euro appartenant aux actionnaires, l'entreprise doit 1,50 \u20ac \u00e0 ses cr\u00e9anciers</div>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"background:var(--surface2);border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">D/E</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Interpr\u00e9tation</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">Peu endett\u00e9 \u2014 solidit\u00e9 rassurante</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">1 \u2013 2</td><td style=\"padding:10px 20px;color:var(--ink2)\">Mod\u00e9r\u00e9 \u2014 levier raisonnable, courant dans l'industrie</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&gt; 2</td><td style=\"padding:10px 20px;color:var(--ink2)\">Attention \u2014 surveiller la capacit\u00e9 de remboursement</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&gt; 3</td><td style=\"padding:10px 20px;color:var(--ink2)\">Risqu\u00e9 \u2014 sauf banques, utilities et REIT (D/E \u00e9lev\u00e9 structurel)</td></tr>\n</table>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:16px 22px;margin:20px 0\">\n<p style=\"font-size:0.88rem;line-height:1.65;color:var(--ink2);margin:0\"><strong>Nuance sectorielle :</strong> Un D/E \u00e9lev\u00e9 chez une entreprise tech est un signal d'alarme. Le m\u00eame D/E chez une banque est parfaitement normal \u2014 leur mod\u00e8le consiste \u00e0 emprunter pour pr\u00eater. Comparez toujours dans le m\u00eame secteur.</p>\n</div>",
  20: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Sant\u00e9 financi\u00e8re</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Dette / EBITDA \u2014 Combien d'ann\u00e9es pour rembourser ?</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le ratio D/E vous dit <em>combien</em> une entreprise a de dettes. Mais il ne r\u00e9pond pas \u00e0 la vraie question des cr\u00e9anciers : <strong>en combien d'ann\u00e9es l'entreprise pourrait-elle rembourser en consacrant tous ses profits op\u00e9rationnels ?</strong> C'est exactement ce que mesure la <strong>Dette Nette / EBITDA</strong>.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">Dette Nette / EBITDA</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Dette nette = Dettes financi\u00e8res totales \u2212 Tr\u00e9sorerie \u00b7 EBITDA = B\u00e9n\u00e9fice avant int\u00e9r\u00eats, imp\u00f4ts, d\u00e9pr\u00e9ciations et amortissements</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La jauge de levier</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"background:var(--surface2);border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Ratio</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Zone</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">0 \u2013 2\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">Confortable \u2014 les banques pr\u00eatent facilement</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">2 \u2013 3\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">Vigilance \u2014 standard acceptable, surveiller l'\u00e9volution</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">3 \u2013 4\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">Tendu \u2014 refinancement difficile, seuil bancaire d\u00e9pass\u00e9</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&gt; 4\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">Zone de danger \u2014 risque de restructuration</td></tr>\n</table>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Les banques int\u00e8grent souvent un <em>covenant</em> exigeant que ce ratio reste sous 3\u00d7. Au-del\u00e0, le pr\u00eat peut \u00eatre d\u00e9clar\u00e9 exigible ou le taux r\u00e9vis\u00e9 \u00e0 la hausse. Ce seuil est donc une information pr\u00e9cieuse sur la libert\u00e9 de man\u0153uvre financi\u00e8re d'une entreprise.</p>",
  21: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Sant\u00e9 financi\u00e8re</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Ratio de Couverture des Int\u00e9r\u00eats \u2014 L'entreprise peut-elle payer ses int\u00e9r\u00eats ?</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Avoir des dettes, c'est accepter de payer des int\u00e9r\u00eats. Si les profits op\u00e9rationnels ne suffisent m\u00eame plus \u00e0 les couvrir, l'entreprise doit puiser dans sa tr\u00e9sorerie \u2014 ou pire, emprunter pour payer ses cr\u00e9anciers. Le <strong>Ratio de Couverture des Int\u00e9r\u00eats (ICR)</strong> mesure pr\u00e9cis\u00e9ment cette capacit\u00e9.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">ICR = EBIT / Charges d'int\u00e9r\u00eats</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Un ICR de 5 signifie que les profits op\u00e9rationnels sont 5 fois sup\u00e9rieurs aux int\u00e9r\u00eats \u00e0 payer</div>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"background:var(--surface2);border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">ICR</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Signification</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&lt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">D\u00e9ficit \u2014 les profits ne couvrent pas les int\u00e9r\u00eats</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">1 \u2013 2</td><td style=\"padding:10px 20px;color:var(--ink2)\">Fragile \u2014 toute baisse des profits cr\u00e9e un d\u00e9ficit</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">2 \u2013 5</td><td style=\"padding:10px 20px;color:var(--ink2)\">Correct \u2014 marge de s\u00e9curit\u00e9 raisonnable</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&gt; 5</td><td style=\"padding:10px 20px;color:var(--ink2)\">Solide \u2014 large coussin, peut absorber un choc \u00e9conomique</td></tr>\n</table>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">L'ICR est le compl\u00e9ment indispensable du D/E. Deux entreprises avec le m\u00eame D/E mais des taux d'int\u00e9r\u00eat tr\u00e8s diff\u00e9rents (2 % vs 8 %) auront des ICR radicalement oppos\u00e9s. En p\u00e9riode de hausse des taux, l'ICR devient critique.</p>",
  22: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le DCF \u2014 Pourquoi 100 \u20ac demain valent moins que 100 \u20ac aujourd'hui</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 7 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le <strong>Discounted Cash Flow (DCF)</strong> est la m\u00e9thode de valorisation fondamentale par excellence. Son principe : une entreprise vaut la somme de tous les flux de tr\u00e9sorerie qu'elle va g\u00e9n\u00e9rer dans le futur, ramen\u00e9s \u00e0 leur valeur d'aujourd'hui.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'intuition : la valeur temps de l'argent</h2>\n<div style=\"background:var(--surface2);border-left:3px solid var(--blue);border-radius:0 6px 6px 0;padding:16px 20px;margin-bottom:20px;font-size:0.88rem;line-height:1.65;color:var(--ink2)\">\n<strong>Trois raisons pour lesquelles 100 \u20ac dans 10 ans valent moins qu'aujourd'hui :</strong><br>\n<span style=\"display:block;margin-top:8px\">\u2460 <strong>L'inflation</strong> \u2014 100 \u20ac ach\u00e8teront moins de biens dans 10 ans.</span>\n<span style=\"display:block;margin-top:4px\">\u2461 <strong>Le risque</strong> \u2014 L'entreprise pourrait ne pas tenir ses promesses.</span>\n<span style=\"display:block;margin-top:4px\">\u2462 <strong>Le co\u00fbt d'opportunit\u00e9</strong> \u2014 100 \u20ac aujourd'hui peuvent \u00eatre investis et cro\u00eetre.</span>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:20px 24px;margin-bottom:24px;text-align:center\">\n<p style=\"font-family:var(--font-serif);font-size:1.05rem;color:var(--ink);margin:0 0 10px\">Valeur = \u03a3 FCF<sub>t</sub> / (1 + r)<sup>t</sup> + Valeur Terminale / (1 + r)<sup>n</sup></p>\n<p style=\"font-size:0.78rem;color:var(--muted);margin:0\">FCF<sub>t</sub> = Free Cash Flow \u00e0 l'ann\u00e9e t \u00b7 r = taux d'actualisation (WACC) \u00b7 n = dur\u00e9e de pr\u00e9vision</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les 3 param\u00e8tres qui font tout</h2>\n<div style=\"display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-bottom:28px\">\n<div style=\"background:var(--surface);border:1px solid var(--border);border-top:3px solid var(--blue);border-radius:6px;padding:14px 16px\">\n<div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--blue);margin-bottom:8px\">FCF pr\u00e9visionnel</div>\n<p style=\"font-size:0.83rem;line-height:1.6;color:var(--ink2);margin:0\">Les flux de tr\u00e9sorerie libres attendus chaque ann\u00e9e, bas\u00e9s sur les revenus et marges futurs.</p>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-top:3px solid var(--teal);border-radius:6px;padding:14px 16px\">\n<div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:8px\">Taux d'actualisation</div>\n<p style=\"font-size:0.83rem;line-height:1.6;color:var(--ink2);margin:0\">Le WACC refl\u00e8te le risque per\u00e7u de l'entreprise et le co\u00fbt de ses financements.</p>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-top:3px solid var(--amber);border-radius:6px;padding:14px 16px\">\n<div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:8px\">Valeur terminale</div>\n<p style=\"font-size:0.83rem;line-height:1.6;color:var(--ink2);margin:0\">La valeur au-del\u00e0 de la p\u00e9riode de pr\u00e9vision \u2014 repr\u00e9sente souvent 60\u201380 % de la valeur totale.</p>\n</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La sensibilit\u00e9 : le talon d'Achille du DCF</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:8px;overflow:hidden;margin-bottom:24px\">\n<div style=\"background:var(--surface2);padding:10px 16px;border-bottom:1px solid var(--border)\"><span style=\"font-size:0.72rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Impact du WACC \u2014 FCF de 100 M\u20ac/an sur 10 ans</span></div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 16px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">WACC</th><th style=\"padding:10px 16px;text-align:right;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Valeur calcul\u00e9e</th><th style=\"padding:10px 16px;text-align:right;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">\u00c9cart vs 8 %</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--ink2)\">6 %</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:600;color:var(--teal)\">1 472 M\u20ac</td><td style=\"padding:10px 16px;text-align:right;color:var(--teal)\">+27 %</td></tr>\n<tr style=\"border-bottom:1px solid var(--border);background:var(--surface2)\"><td style=\"padding:10px 16px;color:var(--ink);font-weight:600\">8 % (base)</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:700\">1 158 M\u20ac</td><td style=\"padding:10px 16px;text-align:right;color:var(--muted)\">\u2014</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--ink2)\">10 %</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:600;color:var(--rose)\">886 M\u20ac</td><td style=\"padding:10px 16px;text-align:right;color:var(--rose)\">\u221223 %</td></tr>\n<tr><td style=\"padding:10px 16px;color:var(--ink2)\">12 %</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:600;color:var(--rose)\">694 M\u20ac</td><td style=\"padding:10px 16px;text-align:right;color:var(--rose)\">\u221240 %</td></tr>\n</table>\n</div>\n<div style=\"background:var(--surface2);border-left:3px solid var(--amber);border-radius:0 6px 6px 0;padding:16px 20px;font-size:0.88rem;line-height:1.65;color:var(--ink2)\"><strong style=\"color:var(--amber)\">\u00c0 retenir :</strong> Une variation de seulement 2 points de WACC peut faire bouger la valorisation de 20 \u00e0 30 %. Le DCF n'est pas une v\u00e9rit\u00e9 \u2014 c'est une <strong>fourchette raisonn\u00e9e</strong>. La rigueur est dans les hypoth\u00e8ses, pas dans la pr\u00e9cision des chiffres.</div>",
  23: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Reverse DCF \u2014 Quelle croissance le march\u00e9 parie-t-il sur ce titre ?</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 6 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le DCF classique part d'hypoth\u00e8ses pour arriver \u00e0 une valeur. Le <strong>Reverse DCF</strong> fait exactement l'inverse : il part du prix actuel de march\u00e9 pour remonter aux hypoth\u00e8ses de croissance que ce prix implique. Une seule question : <em>est-ce que ces hypoth\u00e8ses sont r\u00e9alistes ?</em></p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le vrai avantage : \u00e9viter de se convaincre soi-m\u00eame</h2>\n<div style=\"background:var(--surface2);border-left:3px solid var(--teal);border-radius:0 6px 6px 0;padding:16px 20px;margin-bottom:20px;font-size:0.88rem;line-height:1.65;color:var(--ink2)\">\n<strong style=\"color:var(--teal)\">Le biais classique du DCF :</strong> on choisit inconsciemment des hypoth\u00e8ses qui confirment une conviction pr\u00e9existante. On veut acheter \u2192 on projette 20 % de croissance \u2192 le DCF dit \"sous-\u00e9valu\u00e9\". Le Reverse DCF coupe court \u00e0 ce biais en testant les hypoth\u00e8ses du march\u00e9, pas les siennes.\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Exemple concret</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:8px;overflow:hidden;margin-bottom:24px\">\n<div style=\"background:var(--surface2);padding:10px 16px;border-bottom:1px solid var(--border)\"><span style=\"font-size:0.72rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Analyse Reverse DCF \u2014 WACC 9 %</span></div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 16px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Sc\u00e9nario</th><th style=\"padding:10px 16px;text-align:right;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Croissance implicite FCF</th><th style=\"padding:10px 16px;text-align:right;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Jugement</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--ink2)\">Cours actuel \u00e9lev\u00e9</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:700;color:var(--rose)\">+24 % / an</td><td style=\"padding:10px 16px;text-align:right;color:var(--rose);font-weight:600\">Exigeant</td></tr>\n<tr style=\"border-bottom:1px solid var(--border);background:var(--surface2)\"><td style=\"padding:10px 16px;color:var(--ink2)\">Cours neutre</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:700;color:var(--amber)\">+15 % / an</td><td style=\"padding:10px 16px;text-align:right;color:var(--amber);font-weight:600\">Raisonnable</td></tr>\n<tr><td style=\"padding:10px 16px;color:var(--ink2)\">Cours d\u00e9cot\u00e9</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:700;color:var(--teal)\">+9 % / an</td><td style=\"padding:10px 16px;text-align:right;color:var(--teal);font-weight:600\">Conservateur</td></tr>\n</table>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les trois conclusions possibles</h2>\n<div style=\"display:flex;flex-direction:column;gap:10px;margin-bottom:28px\">\n<div style=\"display:flex;align-items:flex-start;gap:12px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:12px 16px\">\n<div style=\"width:8px;height:8px;border-radius:50%;background:var(--teal);flex-shrink:0;margin-top:5px\"></div>\n<p style=\"font-size:0.88rem;line-height:1.6;color:var(--ink2);margin:0\"><strong style=\"color:var(--teal)\">Hypoth\u00e8ses conservatrices</strong> \u2014 le march\u00e9 sous-estime la croissance probable \u2192 signal d'opportunit\u00e9 potentielle.</p>\n</div>\n<div style=\"display:flex;align-items:flex-start;gap:12px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:12px 16px\">\n<div style=\"width:8px;height:8px;border-radius:50%;background:var(--amber);flex-shrink:0;margin-top:5px\"></div>\n<p style=\"font-size:0.88rem;line-height:1.6;color:var(--ink2);margin:0\"><strong style=\"color:var(--amber)\">Hypoth\u00e8ses raisonnables</strong> \u2014 le prix refl\u00e8te correctement les fondamentaux.</p>\n</div>\n<div style=\"display:flex;align-items:flex-start;gap:12px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:12px 16px\">\n<div style=\"width:8px;height:8px;border-radius:50%;background:var(--rose);flex-shrink:0;margin-top:5px\"></div>\n<p style=\"font-size:0.88rem;line-height:1.6;color:var(--ink2);margin:0\"><strong style=\"color:var(--rose)\">Hypoth\u00e8ses irr\u00e9alistes</strong> \u2014 le prix int\u00e8gre une perfection improbable \u2192 risque de d\u00e9ception et re-rating.</p>\n</div>\n</div>\n<div style=\"background:var(--surface2);border-left:3px solid var(--amber);border-radius:0 6px 6px 0;padding:16px 20px;font-size:0.88rem;line-height:1.65;color:var(--ink2)\"><strong style=\"color:var(--amber)\">En r\u00e9sum\u00e9 :</strong> Le Reverse DCF discipline l'analyse. Il force l'investisseur \u00e0 confronter son optimisme \u00e0 la r\u00e9alit\u00e9 math\u00e9matique du prix, et \u00e0 formuler clairement pourquoi il pense que le march\u00e9 a tort \u2014 ou raison.</div>",
});


// ── Articles supplémentaires 24-53 ──────────────────────────────────────────
Object.assign(_articleData, {
  24: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">EV / EBITDA \u2014 Le multiple universel des analystes</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Parmi tous les multiples de valorisation, l'EV/EBITDA est celui que les analystes professionnels utilisent le plus pour comparer des entreprises \u00e0 travers le monde. Il r\u00e9pond \u00e0 une question simple : <strong style=\"color:var(--ink)\">combien de fois ses profits d'exploitation vaut l'entreprise enti\u00e8re</strong>, en faisant abstraction de ses choix de financement et de sa fiscalit\u00e9 ?</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La valeur d'entreprise (Enterprise Value)</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">L'EV (Enterprise Value) mesure la valeur totale de l'entreprise \u2014 ce qu'il faudrait d\u00e9bourser pour l'acqu\u00e9rir int\u00e9gralement. Elle inclut non seulement la capitalisation boursi\u00e8re, mais aussi la dette nette (dettes financi\u00e8res moins la tr\u00e9sorerie).</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">EV = Capitalisation boursi\u00e8re + Dette nette (+ Int\u00e9r\u00eats minoritaires + Pr\u00e9f\u00e9rentielles)</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">La dette nette = dettes financi\u00e8res totales \u2212 tr\u00e9sorerie disponible</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'EBITDA : les profits avant tout le reste</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">L'EBITDA (Earnings Before Interest, Taxes, Depreciation & Amortization) repr\u00e9sente les profits op\u00e9rationnels avant d\u00e9duction des int\u00e9r\u00eats, imp\u00f4ts, d\u00e9pr\u00e9ciations et amortissements. C'est un proxy du <strong style=\"color:var(--ink)\">flux de tr\u00e9sorerie op\u00e9rationnel brut</strong> de l'entreprise.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">EV / EBITDA = Valeur d'entreprise / EBITDA</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Un ratio de 10\u00d7 signifie que l'entreprise vaut 10 fois ses profits bruts annuels</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Pourquoi pr\u00e9f\u00e9rer l'EV/EBITDA au P/E ?</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le P/E souffre de plusieurs biais : il est affect\u00e9 par la structure de la dette (les int\u00e9r\u00eats p\u00e8sent sur le b\u00e9n\u00e9fice net), la fiscalit\u00e9 (les taux d'imposition varient selon les pays) et les r\u00e8gles comptables d'amortissement. L'EV/EBITDA neutralise ces trois effets, ce qui en fait un outil de comparaison <strong style=\"color:var(--ink)\">international et multi-sectoriel</strong> beaucoup plus fiable.</p>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Technologie / SaaS</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">20\u201340\u00d7</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Croissance forte, marges \u00e9lev\u00e9es</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Industrie</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">8\u201314\u00d7</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Actifs lourds, cycles marqu\u00e9s</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Grande distribution</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">5\u20139\u00d7</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Marges comprim\u00e9es, volumes \u00e9lev\u00e9s</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Ses limites : attention au CapEx</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">L'EBITDA ignore les d\u00e9penses d'investissement (CapEx). Une entreprise tr\u00e8s capitalistique \u2014 construisant des usines ou des r\u00e9seaux \u2014 peut afficher un EBITDA \u00e9lev\u00e9 mais consommer tout ce cash en investissements. Dans ce cas, l'EV/EBITDA surestime la valeur r\u00e9elle. Il faut lui pr\u00e9f\u00e9rer l'EV/EBIT ou l'EV/FCF pour les industries intensives en capital.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:8px\">Pi\u00e8ge \u00e0 \u00e9viter</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Un EV/EBITDA bas n'est pas toujours une aubaine. Une entreprise cyclique en haut de cycle ou une soci\u00e9t\u00e9 qui sous-investit peut afficher un ratio faible. Toujours contextualiser avec la qualit\u00e9 des actifs et la dynamique sectorielle.</p>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">L'EV/EBITDA est le multiple de r\u00e9f\u00e9rence des analystes pour comparer des entreprises sans biais li\u00e9 \u00e0 la dette, la fiscalit\u00e9 ou les amortissements. Il s'interpr\u00e8te toujours en contexte sectoriel : un ratio de 12\u00d7 peut \u00eatre bon dans l'industrie mais faible dans le logiciel.</p>\n</div>\n",
  25: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">EV / EBIT \u2014 La valorisation qui respecte la r\u00e9alit\u00e9 comptable</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">L'EV/EBIT est souvent la r\u00e9ponse aux limites de l'EV/EBITDA. En r\u00e9int\u00e9grant les amortissements dans le d\u00e9nominateur, il tient compte du co\u00fbt r\u00e9el de l'usure des actifs \u2014 un \u00e9l\u00e9ment que l'EBITDA occulte d\u00e9lib\u00e9r\u00e9ment, parfois au d\u00e9triment de la r\u00e9alit\u00e9 \u00e9conomique.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">EBIT vs EBITDA : une seule diff\u00e9rence, mais d\u00e9cisive</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">L'EBIT (Earnings Before Interest and Taxes) est le r\u00e9sultat op\u00e9rationnel : il d\u00e9duit les d\u00e9pr\u00e9ciations et amortissements (D&A) l\u00e0 o\u00f9 l'EBITDA les ignore. Cette diff\u00e9rence peut sembler mineure, mais pour les entreprises \u00e0 forte intensit\u00e9 capitalistique \u2014 industrie lourde, t\u00e9l\u00e9coms, immobilier \u2014 elle est consid\u00e9rable.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">EV / EBIT = Valeur d'entreprise / R\u00e9sultat op\u00e9rationnel (EBIT)</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">L'EBIT = EBITDA \u2212 D\u00e9pr\u00e9ciations & Amortissements</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Quand l'EV/EBIT est-il plus pertinent ?</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Pour une entreprise dont les actifs s'usent r\u00e9ellement \u2014 une cha\u00eene de restaurants avec ses \u00e9quipements, un r\u00e9seau de distribution avec ses camions \u2014 les amortissements ne sont pas une simple ligne comptable mais le reflet d'un besoin futur de r\u00e9investissement. Dans ce cas, l'EV/EBIT capture mieux la r\u00e9alit\u00e9 \u00e9conomique que l'EV/EBITDA.</p>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">T\u00e9l\u00e9coms</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">10\u201318\u00d7</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">CapEx r\u00e9seau \u00e9lev\u00e9, D&A importants</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Industrie lourde</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">7\u201313\u00d7</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Actifs industriels qui s'amortissent</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Logiciel / SaaS</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">20\u201335\u00d7</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Peu d'actifs physiques, D&A faibles</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">EV/EBIT et imp\u00f4ts : une proximit\u00e9 avec la valeur r\u00e9elle</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">L'EBIT est \u00e9galement la base de calcul de l'imp\u00f4t. Un EV/EBIT de 15\u00d7 pour une entreprise tax\u00e9e \u00e0 25 % implique un P/E implicite d'environ 20\u00d7 (15 \u00d7 100/75). Cela permet de <strong style=\"color:var(--ink)\">relier rapidement le multiple d'entreprise au multiple actionnaire</strong>, ce que l'EV/EBITDA ne permet pas directement.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:8px\">\u00c0 noter</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">L'EV/EBIT reste peu adapt\u00e9 aux entreprises en forte croissance qui investissent massivement. Dans ce cas, les amortissements gonflent le d\u00e9nominateur et font para\u00eetre le multiple \u00e9lev\u00e9 alors que l'entreprise construit de la valeur pour l'avenir.</p>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">L'EV/EBIT est plus conservateur que l'EV/EBITDA car il respecte le co\u00fbt comptable de l'usure des actifs. Il est particuli\u00e8rement adapt\u00e9 aux industries capitalistiques o\u00f9 les amortissements refl\u00e8tent un besoin r\u00e9el de r\u00e9investissement.</p>\n</div>\n",
  26: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le CAPE \u2014 Le P/E ajust\u00e9 au cycle \u00e9conomique</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 7 min \u00b7 Niveau : Avanc\u00e9</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">En 1988, Robert Shiller et John Campbell publient un indicateur qui va bouleverser l'analyse des march\u00e9s boursiers : le CAPE (Cyclically Adjusted Price-to-Earnings Ratio), aussi appel\u00e9 Shiller P/E. L'id\u00e9e fondatrice est simple mais profonde : <strong style=\"color:var(--ink)\">un seul exercice fiscal est trop court pour \u00e9valuer la rentabilit\u00e9 r\u00e9elle d'une entreprise ou d'un march\u00e9</strong>.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La construction du CAPE</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le CAPE compare le prix actuel du march\u00e9 aux b\u00e9n\u00e9fices r\u00e9els moyens des 10 derni\u00e8res ann\u00e9es, ajust\u00e9s \u00e0 l'inflation. Cette fen\u00eatre d\u00e9cennale a pour but de lisser les cycles \u00e9conomiques \u2014 \u00e9vitant ainsi que les pics de profits en haut de cycle ou les creux en bas de cycle ne faussent la valorisation.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">CAPE = Prix actuel / Moyenne des BNA r\u00e9els sur 10 ans</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Les BNA (B\u00e9n\u00e9fices Net par Action) sont d\u00e9flat\u00e9s via l'IPC pour comparaison homog\u00e8ne dans le temps</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Pourquoi 10 ans ?</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Un cycle \u00e9conomique complet s'\u00e9tend g\u00e9n\u00e9ralement sur 7 \u00e0 10 ans, incluant expansion et r\u00e9cession. En moyennant les b\u00e9n\u00e9fices sur cette p\u00e9riode, le CAPE capture un <strong style=\"color:var(--ink)\">niveau normalis\u00e9</strong> de la rentabilit\u00e9 des entreprises, ind\u00e9pendant de la phase conjoncturelle. Un P/E classique calcul\u00e9 en pleine r\u00e9cession sera artificiellement \u00e9lev\u00e9 (b\u00e9n\u00e9fices d\u00e9prim\u00e9s) ; en pleine euphorie, artificiellement bas.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Interpr\u00e9tation historique sur le S&P 500</h2>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Moyenne historique</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">~16\u201317\u00d7</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">S&P 500 depuis 1880</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Niveau pr\u00e9occupant</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--rose)\">>25\u00d7</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Signale souvent une sur\u00e9valuation</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Niveau attractif</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\"><12\u00d7</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Rare depuis 1990, zones d'opportunit\u00e9</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les critiques l\u00e9gitimes du CAPE</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le CAPE n'est pas sans d\u00e9fauts. Les r\u00e8gles comptables ont \u00e9volu\u00e9 depuis 1880 \u2014 notamment les normes d'amortissement et de reconnaissance des revenus \u2014 ce qui rend les comparaisons historiques imparfaites. De plus, les taux d'int\u00e9r\u00eat structurellement bas des ann\u00e9es 2010-2020 justifient math\u00e9matiquement des CAPE plus \u00e9lev\u00e9s : quand le taux sans risque est quasi nul, les actifs risqu\u00e9s peuvent l\u00e9gitimement se payer plus cher.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Malgr\u00e9 ces critiques, le CAPE reste l'un des <strong style=\"color:var(--ink)\">meilleurs pr\u00e9dicteurs des rendements boursiers \u00e0 10 ans</strong> : corr\u00e9lation de \u22120,6 avec les performances ult\u00e9rieures sur le S&P 500 dans les \u00e9tudes de Shiller.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:8px\">Mauvais outil de timing</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Un CAPE \u00e9lev\u00e9 ne pr\u00e9dit pas un krach imminent \u2014 il peut rester \u00e9lev\u00e9 pendant des ann\u00e9es. Shiller lui-m\u00eame a r\u00e9p\u00e9t\u00e9 que le CAPE est un outil de valorisation \u00e0 long terme, non un signal tactique de court terme.</p>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le CAPE lisse les b\u00e9n\u00e9fices sur 10 ans pour \u00e9liminer les distorsions cycliques. Historiquement, un CAPE \u00e9lev\u00e9 pr\u00e9dit des rendements boursiers futurs plus faibles sur 10 ans. Ce n'est pas un outil de market timing mais un indicateur structurel de valorisation de march\u00e9.</p>\n</div>\n",
  27: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La valeur intrins\u00e8que selon Graham</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 6 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Benjamin Graham \u2014 p\u00e8re de l'investissement value et mentor de Warren Buffett \u2014 a cherch\u00e9 toute sa vie une formule simple pour estimer la valeur intrins\u00e8que d'une action sans avoir \u00e0 projeter des flux de tr\u00e9sorerie complexes. Dans <em>The Intelligent Investor</em> (1962), il propose une \u00e9quation qui tient en une ligne.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La formule de Graham (version r\u00e9vis\u00e9e 1974)</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">V = BNA \u00d7 (8,5 + 2g) \u00d7 (4,4 / Y)</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">BNA = B\u00e9n\u00e9fice Net par Action \u00b7 g = taux de croissance annuel attendu sur 7-10 ans (%) \u00b7 Y = rendement des obligations AAA \u00e0 20 ans (%)</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La constante 8,5 repr\u00e9sente le P/E d'une entreprise \u00e0 croissance nulle. Le facteur 2g valorise la croissance future. Le ratio 4,4/Y ajuste la valeur en fonction du niveau des taux d'int\u00e9r\u00eat \u2014 4,4 % \u00e9tant le taux AAA de r\u00e9f\u00e9rence de Graham en 1962.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Exemple concret</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Entreprise A : BNA de 5 \u20ac, croissance attendue de 8 %, taux AAA actuel de 5,5 %. V = 5 \u00d7 (8,5 + 16) \u00d7 (4,4/5,5) = 5 \u00d7 24,5 \u00d7 0,8 = <strong style=\"color:var(--ink)\">98 \u20ac</strong>. Si le titre cote 75 \u20ac, il traite avec une marge de s\u00e9curit\u00e9 de ~23 %.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La marge de s\u00e9curit\u00e9 : le c\u0153ur de la philosophie Graham</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Graham n'investit jamais au prix exact de la valeur intrins\u00e8que. Il exige une <strong style=\"color:var(--ink)\">marge de s\u00e9curit\u00e9 d'au moins 30 \u00e0 50 %</strong> entre le prix de march\u00e9 et la valeur calcul\u00e9e. Cette prudence int\u00e8gre l'incertitude des hypoth\u00e8ses de croissance et prot\u00e8ge contre les erreurs d'analyse.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">Forces de la formule</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Simplicit\u00e9</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Applicable en quelques secondes</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Int\u00e9gration des taux</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Ajustement automatique au contexte macro</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Discipline</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">\u00c9vite les histoires \u2014 seuls les chiffres comptent</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:10px\">Limites</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Estimation de g</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">La croissance future est toujours incertaine</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Peu adapt\u00e9e aux pertes</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">BNA n\u00e9gatif donne une valeur absurde</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Secteurs atypiques</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Banques, assurances, utilities difficiles \u00e0 \u00e9valuer</span></div>\n    </div>\n  </div>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:8px\">Contexte des taux</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Avec des taux AAA tr\u00e8s \u00e9lev\u00e9s (>7 %), le facteur 4,4/Y comprime fortement la valeur intrins\u00e8que, rendant presque tout sur\u00e9valu\u00e9. Avec des taux tr\u00e8s bas (<2 %), le facteur gonfle artificiellement les valorisations. Graham lui-m\u00eame a reconnu les limites de son mod\u00e8le dans des environnements de taux extr\u00eames.</p>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">La formule de Graham offre une valorisation rapide et disciplin\u00e9e int\u00e9grant croissance et taux d'int\u00e9r\u00eat. Elle n'est pas un oracle mais un filtre : les titres en dessous de leur valeur Graham m\u00e9ritent une analyse approfondie ; ceux au-dessus demandent une justification solide.</p>\n</div>\n",
  28: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Somme des Parties (SotP) \u2014 Valoriser les conglom\u00e9rats</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 7 min \u00b7 Niveau : Avanc\u00e9</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Certaines entreprises d\u00e9fient toute valorisation simple : elles op\u00e8rent dans plusieurs secteurs radicalement diff\u00e9rents, avec des profils de risque et de croissance incompatibles. Pour ces conglom\u00e9rats et holdings, la <strong style=\"color:var(--ink)\">Somme des Parties</strong> (Sum of the Parts, SotP) est la seule approche intellectuellement honn\u00eate.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le principe</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La SotP consiste \u00e0 valoriser chaque division ou filiale de l'entreprise s\u00e9par\u00e9ment, en utilisant le multiple le plus adapt\u00e9 \u00e0 son secteur, puis \u00e0 sommer ces valeurs pour obtenir la valeur totale d'entreprise. On en d\u00e9duit ensuite la dette nette du groupe pour obtenir la valeur des capitaux propres.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Valeur totale = \u03a3 (EV de chaque segment) \u2212 Dette nette consolid\u00e9e</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Chaque segment est valoris\u00e9 avec le multiple sectoriel appropri\u00e9 (EV/EBITDA, EV/Rev, P/E\u2026)</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Exemple : un groupe diversifi\u00e9</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Imaginez un conglom\u00e9rat avec trois divisions : logiciel (EBITDA 200 M\u20ac \u00d7 20\u00d7 = 4 Md\u20ac), distribution (EBITDA 150 M\u20ac \u00d7 7\u00d7 = 1,05 Md\u20ac), immobilier (actif net r\u00e9\u00e9valu\u00e9 = 800 M\u20ac). Total EV = 5,85 Md\u20ac. Avec une dette nette de 1,2 Md\u20ac, la valeur des capitaux propres est de 4,65 Md\u20ac.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La d\u00e9cote de conglom\u00e9rat</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Dans la r\u00e9alit\u00e9, les march\u00e9s appliquent souvent une <strong style=\"color:var(--ink)\">d\u00e9cote de conglom\u00e9rat</strong> de 10 \u00e0 30 % par rapport \u00e0 la somme des parties. Cette d\u00e9cote refl\u00e8te : la complexit\u00e9 de gestion, les conflits d'allocation du capital entre divisions, la prime de diversification non d\u00e9sir\u00e9e par les investisseurs (qui pr\u00e9f\u00e8rent diversifier eux-m\u00eames), et le manque de transparence.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">Avantages de la SotP</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Pr\u00e9cision sectorielle</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Chaque segment valoris\u00e9 au juste multiple</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Identification d'actifs cach\u00e9s</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">R\u00e9v\u00e8le les filiales sous-valoris\u00e9es</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Base pour M&A</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Fondement des dossiers de cession partielle</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:10px\">Difficult\u00e9s pratiques</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Co\u00fbts si\u00e8ge non allou\u00e9s</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Comment r\u00e9partir les frais centraux ?</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Synergies</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Comptabilis\u00e9es ou non dans chaque segment ?</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Donn\u00e9es segment\u00e9es</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Souvent incompl\u00e8tes ou non comparables</span></div>\n    </div>\n  </div>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">La SotP est incontournable pour les conglom\u00e9rats, holdings et entreprises multi-segments. Elle exige des donn\u00e9es segment\u00e9es fiables et une bonne ma\u00eetrise des multiples sectoriels. La d\u00e9cote de conglom\u00e9rat (souvent 15-25 %) doit \u00eatre int\u00e9gr\u00e9e dans l'analyse finale.</p>\n</div>\n",
  29: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le ROA \u2014 La rentabilit\u00e9 totale des actifs</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le ROE mesure l'efficacit\u00e9 vis-\u00e0-vis des actionnaires ; le ROA (Return on Assets) mesure l'efficacit\u00e9 vis-\u00e0-vis de <em>tous</em> les apporteurs de capital. Il r\u00e9pond \u00e0 la question : <strong style=\"color:var(--ink)\">combien chaque euro d'actif g\u00e9n\u00e8re-t-il de profit</strong>, ind\u00e9pendamment de la fa\u00e7on dont ces actifs sont financ\u00e9s ?</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">ROA = B\u00e9n\u00e9fice net / Total des actifs \u00d7 100</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Le total des actifs repr\u00e9sente l'int\u00e9gralit\u00e9 des ressources \u00e9conomiques de l'entreprise</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">ROA vs ROE : neutraliser l'effet de levier</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La grande force du ROA est qu'il <strong style=\"color:var(--ink)\">neutralise l'effet de levier financier</strong>. Rappelons la d\u00e9composition DuPont : ROE = ROA \u00d7 Levier financier. Une entreprise avec un ROE de 20 % peut avoir un ROA de 5 % (fort endettement) ou de 15 % (peu de dettes). Le ROA r\u00e9v\u00e8le quelle partie du rendement vient de la performance op\u00e9rationnelle r\u00e9elle.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Benchmarks sectoriels</h2>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Banques</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">0,8\u20131,5 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Actifs gigantesques (pr\u00eats)</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Industrie</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">4\u201310 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Actifs physiques importants</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Logiciel / SaaS</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">10\u201325 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Peu d'actifs physiques</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La version corrig\u00e9e : utiliser l'EBIT au num\u00e9rateur</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Pour comparer des entreprises avec des structures de dette diff\u00e9rentes, certains analystes pr\u00e9f\u00e8rent calculer le ROA avec l'EBIT (r\u00e9sultat avant int\u00e9r\u00eats et imp\u00f4ts) au num\u00e9rateur. Cela donne un ROA qui mesure purement l'efficacit\u00e9 op\u00e9rationnelle des actifs, sans contamination par la dette.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:8px\">Attention aux actifs incorporels</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Les entreprises qui ont r\u00e9alis\u00e9 des acquisitions \u00e0 prime pr\u00e9sentent des actifs gonfl\u00e9s par le goodwill. Leur ROA peut sembler faible alors que leurs op\u00e9rations sont efficaces. Toujours v\u00e9rifier la composition du bilan.</p>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le ROA mesure l'efficacit\u00e9 globale de l'outil \u00e9conomique, sans biais li\u00e9 \u00e0 la structure financi\u00e8re. Un ROA en progression signifie que l'entreprise exploite ses actifs de plus en plus efficacement. La comparaison ROA/ROE r\u00e9v\u00e8le le r\u00f4le de la dette dans la performance des actionnaires.</p>\n</div>\n",
  30: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le ROIC \u2014 Le test ultime de la cr\u00e9ation de valeur</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 6 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Warren Buffett l'appelle \u00ab le ratio le plus important en finance \u00bb. Le ROIC (Return on Invested Capital) mesure la rentabilit\u00e9 du capital r\u00e9ellement investi dans l'activit\u00e9 \u2014 pas de la totalit\u00e9 du bilan, mais uniquement des capitaux <em>engag\u00e9s dans les op\u00e9rations</em>. C'est le test d\u00e9cisif : <strong style=\"color:var(--ink)\">l'entreprise cr\u00e9e-t-elle de la valeur ou la d\u00e9truit-elle ?</strong></p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">ROIC = NOPAT / Capital investi \u00d7 100</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">NOPAT = Net Operating Profit After Tax = EBIT \u00d7 (1 \u2212 taux d'imposition) \u00b7 Capital investi = Capitaux propres + Dette nette</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">ROIC et WACC : la condition de cr\u00e9ation de valeur</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La r\u00e8gle fondamentale est simple : si ROIC > WACC (co\u00fbt moyen pond\u00e9r\u00e9 du capital), l'entreprise <strong style=\"color:var(--ink)\">cr\u00e9e de la valeur</strong>. Si ROIC < WACC, chaque euro investi d\u00e9truit de la richesse. C'est cette diff\u00e9rence \u2014 le <em>spread</em> ROIC/WACC \u2014 qui d\u00e9termine si la croissance est b\u00e9n\u00e9fique ou nuisible pour les actionnaires.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">ROIC > WACC \u2192 Valeur cr\u00e9\u00e9e</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Chaque projet rentable</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">La croissance est souhaitable</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Moat \u00e9conomique solide</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Avantage concurrentiel durable</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Actions m\u00e9ritent une prime</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Multiple \u00e9lev\u00e9 justifi\u00e9</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:10px\">ROIC < WACC \u2192 Valeur d\u00e9truite</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Croissance \u00e0 \u00e9viter</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Grandir d\u00e9truit de la valeur</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Retour aux actionnaires</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Dividendes et rachats pr\u00e9f\u00e9rables</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Restructuration n\u00e9cessaire</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Recentrage sur les activit\u00e9s rentables</span></div>\n    </div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le ROIC r\u00e9v\u00e8le les v\u00e9ritables foss\u00e9s \u00e9conomiques</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Les entreprises avec un ROIC durablement sup\u00e9rieur \u00e0 15 % disposent d'un <em>moat</em> \u2014 un avantage concurrentiel structurel qui emp\u00eache la concurrence d'\u00e9roder leurs marges. Microsoft, LVMH, Herm\u00e8s maintiennent des ROIC de 20-40 % depuis des d\u00e9cennies, signe d'avantages difficiles \u00e0 r\u00e9pliquer : marques, effets r\u00e9seau, co\u00fbts de switch \u00e9lev\u00e9s.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le ROIC est le ratio le plus complet pour \u00e9valuer la qualit\u00e9 d'une entreprise : il mesure la rentabilit\u00e9 des capitaux r\u00e9ellement engag\u00e9s dans l'activit\u00e9. Un ROIC durablement sup\u00e9rieur au WACC est la signature d'un avantage concurrentiel solide et d'une cr\u00e9ation de valeur r\u00e9elle pour les actionnaires.</p>\n</div>\n",
  31: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le ROCE \u2014 Le rendement du capital employ\u00e9</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Souvent confondu avec le ROIC, le ROCE (Return on Capital Employed) est la mesure de r\u00e9f\u00e9rence dans les industries europ\u00e9ennes et les secteurs \u00e0 forte intensit\u00e9 capitalistique. Sa particularit\u00e9 : il utilise le capital employ\u00e9 au d\u00e9nominateur, une d\u00e9finition l\u00e9g\u00e8rement diff\u00e9rente du capital investi.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">ROCE = EBIT / Capital employ\u00e9 \u00d7 100</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Capital employ\u00e9 = Total des actifs \u2212 Passifs courants (= Actifs non courants + BFR)</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Diff\u00e9rence ROCE / ROIC</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La distinction tient \u00e0 deux points : le ROCE utilise l'EBIT (avant imp\u00f4ts) l\u00e0 o\u00f9 le ROIC utilise le NOPAT (apr\u00e8s imp\u00f4ts), et la d\u00e9finition du d\u00e9nominateur diff\u00e8re l\u00e9g\u00e8rement. En pratique, les deux indicateurs convergent et sont souvent utilis\u00e9s de fa\u00e7on interchangeable. Le ROCE est plus fr\u00e9quent en Europe, le ROIC davantage aux \u00c9tats-Unis.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Particuli\u00e8rement utile pour les industries lourdes</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Les entreprises p\u00e9troli\u00e8res, les cimentiers, les op\u00e9rateurs de r\u00e9seaux d'\u00e9nergie \u2014 tous \u00e9valuent leurs projets via le ROCE. Dans ces industries, le capital employ\u00e9 est immense et les cycles longs. Un ROCE sup\u00e9rieur au co\u00fbt du capital (g\u00e9n\u00e9ralement 8-12 % dans ces secteurs) justifie les investissements.</p>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c9nergie</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">8\u201315 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Cycles longs, CapEx massif</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Industrie chimique</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">12\u201320 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Capital \u00e9lev\u00e9, marges stables</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Utilities</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">5\u201310 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">R\u00e9gul\u00e9, rendement contraint</div>\n  </div>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le ROCE mesure l'efficacit\u00e9 du capital total employ\u00e9 dans les op\u00e9rations. C'est la mesure phare des industries \u00e0 forte intensit\u00e9 capitalistique. Comme le ROIC, il doit \u00eatre compar\u00e9 au co\u00fbt du capital pour d\u00e9terminer si l'entreprise cr\u00e9e ou d\u00e9truit de la valeur.</p>\n</div>\n",
  32: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Marge Brute \u2014 La premi\u00e8re ligne de profitabilit\u00e9</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Avant de parler de marge op\u00e9rationnelle ou nette, il existe une \u00e9tape encore plus fondamentale : la <strong style=\"color:var(--ink)\">marge brute</strong>. Elle mesure ce qui reste du chiffre d'affaires apr\u00e8s avoir soustrait le co\u00fbt direct de production \u2014 le co\u00fbt des marchandises vendues (COGS). C'est la fondation sur laquelle repose toute la rentabilit\u00e9 future.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Marge brute = (CA \u2212 Co\u00fbt des ventes) / CA \u00d7 100</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Co\u00fbt des ventes (COGS) = mati\u00e8res premi\u00e8res, main-d'\u0153uvre directe, co\u00fbts de fabrication directs</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Qu'est-ce que le co\u00fbt des ventes ?</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le COGS (Cost of Goods Sold) regroupe uniquement les co\u00fbts <em>directement li\u00e9s</em> \u00e0 la production ou \u00e0 la vente : mati\u00e8res premi\u00e8res, salaires des ouvriers en production, frais d'emballage, co\u00fbts de fabrication. Il ne comprend pas les frais g\u00e9n\u00e9raux (marketing, administration, R&D) qui sont d\u00e9duits plus bas dans le compte de r\u00e9sultat.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Disparit\u00e9s sectorielles extr\u00eames</h2>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Logiciel</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">70\u201390 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Co\u00fbt marginal quasi nul</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Luxe</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">55\u201375 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Mat\u00e9riaux premium, mais pricing power fort</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Agroalimentaire</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">30\u201355 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Mati\u00e8res premi\u00e8res volatiles</div>\n  </div>\n</div>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Automobile</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">15\u201325 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Acier, composants, assemblage</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Grande distribution</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">20\u201335 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Achat/revente \u00e0 faible marge</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Restauration rapide</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">25\u201340 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Ingr\u00e9dients + main-d'\u0153uvre</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La marge brute comme signal de pricing power</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Une marge brute \u00e9lev\u00e9e et stable \u2014 ou en progression \u2014 est le signe d'un <strong style=\"color:var(--ink)\">pricing power solide</strong> : l'entreprise peut r\u00e9percuter ses hausses de co\u00fbts sur ses clients sans perdre de volumes. \u00c0 l'inverse, une marge brute qui se comprime progressivement signale soit une intensification de la concurrence, soit une vuln\u00e9rabilit\u00e9 aux co\u00fbts des mati\u00e8res premi\u00e8res.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">La marge brute est le premier test de la viabilit\u00e9 d'un mod\u00e8le \u00e9conomique. Une marge brute \u00e9lev\u00e9e donne de la flexibilit\u00e9 pour investir en R&D, marketing et distribution. Une marge brute faible n\u00e9cessite des volumes tr\u00e8s \u00e9lev\u00e9s pour d\u00e9gager une rentabilit\u00e9 finale acceptable.</p>\n</div>\n",
  33: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Marge EBITDA \u2014 Le proxy du flux de tr\u00e9sorerie op\u00e9rationnel</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La marge EBITDA est l'une des premi\u00e8res m\u00e9triques regard\u00e9es par les analystes lors d'une analyse sectorielle. Avant m\u00eame de regarder le b\u00e9n\u00e9fice net ou le free cash flow, ils regardent cette marge pour \u00e9valuer l'efficacit\u00e9 op\u00e9rationnelle brute d'une entreprise, en faisant abstraction de sa structure financi\u00e8re et de ses politiques comptables d'amortissement.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Marge EBITDA = EBITDA / Chiffre d'affaires \u00d7 100</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">EBITDA = R\u00e9sultat op\u00e9rationnel + Amortissements = proxy du flux de tr\u00e9sorerie op\u00e9rationnel brut</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Position dans la cascade de rentabilit\u00e9</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La marge EBITDA se situe entre la marge brute (qui ne d\u00e9duit que les COGS) et la marge op\u00e9rationnelle (qui d\u00e9duit aussi les D&A). Elle refl\u00e8te l'efficacit\u00e9 commerciale et organisationnelle, mais avant la politique d'investissement (captur\u00e9e par les D&A).</p>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Logiciel / SaaS</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">20\u201345 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Mod\u00e8le scalable, co\u00fbts fixes</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Pharmacie</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">25\u201340 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Brevets, R&D \u00e9lev\u00e9 mais rentable</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Industrie</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">10\u201320 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Co\u00fbts fixes + variables</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Utilit\u00e9 dans la valorisation par EV/EBITDA</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La marge EBITDA est indissociable du multiple EV/EBITDA. Pour un m\u00eame multiple, une entreprise avec une marge EBITDA de 35 % est structurellement diff\u00e9rente d'une avec 12 % : les capacit\u00e9s d'investissement, de d\u00e9sendettement et de g\u00e9n\u00e9ration de cash libre sont radicalement diff\u00e9rentes.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:8px\">Ne pas confondre EBITDA et cash flow</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">L'EBITDA est souvent pr\u00e9sent\u00e9 comme un proxy du cash flow, mais il ignore le BFR (Besoin en Fonds de Roulement) et le CapEx. Une entreprise peut avoir un EBITDA \u00e9lev\u00e9 et g\u00e9n\u00e9rer peu de cash libre si elle a des besoins en BFR importants ou investit massivement.</p>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">La marge EBITDA mesure l'efficacit\u00e9 op\u00e9rationnelle avant amortissements, int\u00e9r\u00eats et imp\u00f4ts. Elle permet des comparaisons sectorielles sans biais comptable. Elle est la base du multiple EV/EBITDA, mais ne remplace pas l'analyse du free cash flow pour \u00e9valuer la g\u00e9n\u00e9ration de liquidit\u00e9s r\u00e9elles.</p>\n</div>\n",
  34: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Flux de tr\u00e9sorerie</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">L'EBITDA \u2014 Le profit avant les arbitrages comptables</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">L'EBITDA (Earnings Before Interest, Taxes, Depreciation and Amortization) est partout dans la finance : dans les communiqu\u00e9s de presse, les pr\u00e9sentations aux investisseurs, les contrats de dette. Comprendre ce qu'il mesure \u2014 et ce qu'il ne mesure pas \u2014 est fondamental pour tout analyste financier.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">EBITDA = R\u00e9sultat net + Imp\u00f4ts + Int\u00e9r\u00eats + D&A</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">D&A = D\u00e9pr\u00e9ciations et Amortissements \u00b7 Ou : EBITDA = EBIT + Amortissements</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Pourquoi exclure int\u00e9r\u00eats, imp\u00f4ts et amortissements ?</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Chacun de ces \u00e9l\u00e9ments introduit un biais dans la comparaison d'entreprises : les <strong style=\"color:var(--ink)\">int\u00e9r\u00eats</strong> d\u00e9pendent des choix de financement (dette vs capitaux propres) ; les <strong style=\"color:var(--ink)\">imp\u00f4ts</strong> varient selon les pays et les optimisations fiscales ; les <strong style=\"color:var(--ink)\">amortissements</strong> d\u00e9pendent des m\u00e9thodes comptables choisies et de l'\u00e2ge des actifs. En les excluant, l'EBITDA permet une comparaison pure de la performance op\u00e9rationnelle.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'EBITDA dans les op\u00e9rations de LBO</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Dans les rachats \u00e0 effet de levier (LBO), l'EBITDA est la m\u00e9trique centrale. Les fonds de private equity valorisent les entreprises en multiple d'EBITDA (typiquement 7-12\u00d7) et structurent la dette en multiple d'EBITDA (4-6\u00d7). L'EBITDA repr\u00e9sente la capacit\u00e9 brute de l'entreprise \u00e0 g\u00e9n\u00e9rer du cash pour rembourser ses cr\u00e9anciers.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">EBITDA est utile pour\u2026</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Comparaisons sectorielles</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Neutralise les biais comptables</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">\u00c9valuation de la dette</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Base du ratio Dette/EBITDA</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">LBO et M&A</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Multiple de valorisation universel</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:10px\">EBITDA est insuffisant pour\u2026</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Cash flow r\u00e9el</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Ignore CapEx et variations BFR</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Industries capital-intensives</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Amortissements = vraie charge</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Comparaisons inter-sectorielles</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">CapEx tr\u00e8s diff\u00e9rent selon les m\u00e9tiers</span></div>\n    </div>\n  </div>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:8px\">Le terme \u00ab EBITDA \u00bb peut \u00eatre manipul\u00e9</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Certaines entreprises ajoutent des termes non-standard \u00e0 leur EBITDA (frais de restructuration, stock-options, co\u00fbts d'acquisition\u2026) pour pr\u00e9senter un \u00ab EBITDA ajust\u00e9 \u00bb flatteur. Toujours lire les notes pour comprendre les retraitements. L'EBITDA non-ajust\u00e9 IFRS/GAAP est la seule m\u00e9trique comparable.</p>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">L'EBITDA mesure la profitabilit\u00e9 op\u00e9rationnelle brute avant les effets du financement, de la fiscalit\u00e9 et des amortissements. C'est la base des valorisations en finance d'entreprise. Mais il ne refl\u00e8te pas le cash g\u00e9n\u00e9r\u00e9 r\u00e9ellement \u2014 il faut y soustraire le CapEx et les variations de BFR pour obtenir le free cash flow.</p>\n</div>\n",
  35: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Flux de tr\u00e9sorerie</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le CapEx \u2014 L'investissement qui construit l'avenir</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Chaque entreprise doit investir pour maintenir et d\u00e9velopper ses capacit\u00e9s productives. Ces investissements en actifs physiques \u2014 machines, b\u00e2timents, \u00e9quipements, infrastructure technologique \u2014 constituent les <strong style=\"color:var(--ink)\">d\u00e9penses d'investissement</strong>, ou CapEx (Capital Expenditures). Comprendre leur nature est essentiel pour \u00e9valuer la qualit\u00e9 d'un business model.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Free Cash Flow = Cash flow op\u00e9rationnel \u2212 CapEx</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Le CapEx appara\u00eet comme emploi de tr\u00e9sorerie dans le tableau des flux de tr\u00e9sorerie</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">CapEx de maintenance vs CapEx de croissance</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La distinction la plus importante : tout CapEx n'est pas cr\u00e9ateur de valeur. Le <strong style=\"color:var(--ink)\">CapEx de maintenance</strong> (ou de remplacement) est la d\u00e9pense minimale pour maintenir l'outil productif existant \u2014 si on ne l'effectue pas, les actifs se d\u00e9gradent et les revenus chutent. Le <strong style=\"color:var(--ink)\">CapEx de croissance</strong>, lui, finance de nouvelles capacit\u00e9s et doit g\u00e9n\u00e9rer un retour sup\u00e9rieur au co\u00fbt du capital.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:10px\">CapEx de maintenance</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Nature</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Remplacement d'actifs existants</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Effet sur la croissance</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Aucun \u2014 pr\u00e9serve le statu quo</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Retour requis</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Indispensable, pas un choix</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">CapEx de croissance</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Nature</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Nouveaux actifs, nouvelles capacit\u00e9s</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Effet sur la croissance</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Doit g\u00e9n\u00e9rer du CA futur</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Retour requis</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Sup\u00e9rieur au WACC pour cr\u00e9er de la valeur</span></div>\n    </div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'intensit\u00e9 capitalistique : un d\u00e9terminant du mod\u00e8le \u00e9conomique</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le ratio CapEx/CA mesure l'intensit\u00e9 des investissements n\u00e9cessaires. Les t\u00e9l\u00e9coms investissent 15-25 % de leur CA en r\u00e9seaux ; le logiciel SaaS investit moins de 5 %. Cette diff\u00e9rence explique pourquoi les multiples de valorisation sont tr\u00e8s diff\u00e9rents : les entreprises capital-l\u00e9g\u00e8res (asset-light) g\u00e9n\u00e8rent plus de free cash flow par euro de CA et m\u00e9ritent des multiples plus \u00e9lev\u00e9s.</p>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">T\u00e9l\u00e9coms</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">15\u201325 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">R\u00e9seau : actif strat\u00e9gique lourd</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Distribution</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">2\u20135 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Peu d'actifs fixes</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Logiciel SaaS</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">2\u20138 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Principalement R&D capitalis\u00e9e</div>\n  </div>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le CapEx est le principal poste de sortie de tr\u00e9sorerie apr\u00e8s l'exploitation. Distinguer maintenance et croissance est crucial : un CapEx de maintenance \u00e9lev\u00e9 r\u00e9duit structurellement le free cash flow disponible. Les business models asset-light g\u00e9n\u00e8rent plus de cash avec moins d'investissements.</p>\n</div>\n",
  36: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Flux de tr\u00e9sorerie</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le BFR \u2014 Le besoin invisible qui mange la tr\u00e9sorerie</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 6 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Une entreprise peut \u00eatre rentable sur le papier et pourtant manquer de liquidit\u00e9s. La cause ? Le <strong style=\"color:var(--ink)\">Besoin en Fonds de Roulement</strong> (BFR) \u2014 ce d\u00e9calage in\u00e9vitable entre les encaissements et les d\u00e9caissements op\u00e9rationnels. Comprendre le BFR, c'est comprendre pourquoi la croissance peut tuer une entreprise.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">BFR = Stocks + Cr\u00e9ances clients \u2212 Dettes fournisseurs</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Le BFR repr\u00e9sente le capital immobilis\u00e9 dans le cycle d'exploitation entre payer les fournisseurs et encaisser les clients</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le cycle d'exploitation expliqu\u00e9</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Toute activit\u00e9 industrielle ou commerciale cr\u00e9e un d\u00e9calage temporel : vous achetez des mati\u00e8res premi\u00e8res (\u2212cash), vous les transformez, vous livrez (et attendez d'\u00eatre pay\u00e9). Pendant ce d\u00e9lai, vous devez financer l'activit\u00e9. Plus le cycle est long, plus le BFR est \u00e9lev\u00e9 \u2014 et plus il faut de capitaux pour financer la croissance.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">BFR positif vs n\u00e9gatif</h2>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:10px\">BFR positif (besoin de financement)</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Industrie manufacturi\u00e8re</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Stocks + d\u00e9lais clients longs</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">B2B avec grandes entreprises</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Conditions de paiement 60-90 jours</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Distribution sp\u00e9cialis\u00e9e</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Stocks \u00e9lev\u00e9s, marges faibles</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">BFR n\u00e9gatif (ressource de financement)</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Grande distribution</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Paie fournisseurs apr\u00e8s avoir encaiss\u00e9</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Abonnements pr\u00e9pay\u00e9s</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Client paye avant la prestation</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Amazon / marketplaces</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Mod\u00e8le de financement par les vendeurs</span></div>\n    </div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">BFR et croissance : la spirale du capital</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Quand une entreprise \u00e0 BFR positif cro\u00eet, son BFR cro\u00eet proportionnellement. Chaque euro de CA suppl\u00e9mentaire immobilise du capital suppl\u00e9mentaire. C'est pourquoi certaines entreprises en forte croissance ont besoin de lever des fonds malgr\u00e9 une rentabilit\u00e9 positive : elles financent leur BFR croissant.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">\u00c0 l'inverse, les entreprises \u00e0 BFR n\u00e9gatif voient leur tr\u00e9sorerie <em>s'am\u00e9liorer</em> quand elles croissent \u2014 un avantage comp\u00e9titif consid\u00e9rable qui explique la puissance du mod\u00e8le de la grande distribution ou des plateformes num\u00e9riques.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le BFR est le capital immobilis\u00e9 dans le cycle d'exploitation. Un BFR positif est un besoin de financement qui cro\u00eet avec le CA ; un BFR n\u00e9gatif est une ressource de financement exceptionnelle (grandes surfaces, abonnements). La gestion du BFR est aussi importante que la rentabilit\u00e9 pour \u00e9valuer la sant\u00e9 financi\u00e8re r\u00e9elle d'une entreprise.</p>\n</div>\n",
  37: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Flux de tr\u00e9sorerie</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Cash Conversion Cycle \u2014 Mesurer l'efficacit\u00e9 du cycle d'exploitation</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 7 min \u00b7 Niveau : Avanc\u00e9</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le Cash Conversion Cycle (CCC), ou cycle de conversion du cash, mesure en jours le temps qui s'\u00e9coule entre le moment o\u00f9 une entreprise d\u00e9caisse pour ses achats et le moment o\u00f9 elle encaisse pour ses ventes. C'est la traduction temporelle du BFR, et un outil indispensable pour comparer l'efficacit\u00e9 op\u00e9rationnelle entre entreprises.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">CCC = DIO + DSO \u2212 DPO</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">DIO (Days Inventory Outstanding) + DSO (Days Sales Outstanding) \u2212 DPO (Days Payable Outstanding)</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les trois composantes du CCC</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\"><strong style=\"color:var(--ink)\">DIO (jours de stocks)</strong> = Stocks / COGS \u00d7 365 \u2014 Temps moyen qu'un produit reste en stock avant d'\u00eatre vendu. Plus c'est court, moins de capital est immobilis\u00e9.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\"><strong style=\"color:var(--ink)\">DSO (jours de cr\u00e9ances)</strong> = Cr\u00e9ances clients / CA \u00d7 365 \u2014 D\u00e9lai moyen entre la vente et l'encaissement. D\u00e9pend du secteur et du pouvoir de n\u00e9gociation vis-\u00e0-vis des clients.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\"><strong style=\"color:var(--ink)\">DPO (jours de dettes)</strong> = Dettes fournisseurs / COGS \u00d7 365 \u2014 D\u00e9lai moyen de paiement aux fournisseurs. Plus c'est long, plus l'entreprise se finance sur ses fournisseurs.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">CCC n\u00e9gatif : le mod\u00e8le id\u00e9al</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Amazon affiche r\u00e9guli\u00e8rement un CCC n\u00e9gatif (\u221230 \u00e0 \u221260 jours) : elle encaisse les clients avant m\u00eame de payer ses fournisseurs. Walmart affiche \u00e9galement un CCC tr\u00e8s faible. Ce mod\u00e8le permet \u00e0 ces entreprises de financer leur croissance avec l'argent de leurs fournisseurs \u2014 un avantage comp\u00e9titif majeur.</p>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Amazon (retail)</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">~\u221230 j</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Encaisse avant de payer</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Fabricant auto</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">60\u201390 j</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Stocks longs + clients B2B</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Pharmacie distribution</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">30\u201360 j</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">D\u00e9lais r\u00e9glementaires</div>\n  </div>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le CCC traduit en jours l'efficacit\u00e9 du cycle d'exploitation. Un CCC court (voire n\u00e9gatif) signifie que l'entreprise immobilise peu de capital dans son cycle op\u00e9rationnel. L'am\u00e9liorer \u2014 r\u00e9duire stocks, acc\u00e9l\u00e9rer les encaissements, allonger les d\u00e9lais fournisseurs \u2014 lib\u00e8re du cash sans toucher \u00e0 la rentabilit\u00e9.</p>\n</div>\n",
  38: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Sant\u00e9 financi\u00e8re</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Current Ratio \u2014 Peut-elle honorer ses dettes \u00e0 court terme ?</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Avant de s'interroger sur la cr\u00e9ation de valeur \u00e0 long terme d'une entreprise, il faut s'assurer qu'elle survivra \u00e0 court terme. Le <strong style=\"color:var(--ink)\">Current Ratio</strong> (ratio de liquidit\u00e9 g\u00e9n\u00e9rale) r\u00e9pond \u00e0 cette question fondamentale : l'entreprise dispose-t-elle d'assez d'actifs liquides pour couvrir ses obligations \u00e0 court terme ?</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Current Ratio = Actifs courants / Passifs courants</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Actifs courants = tr\u00e9sorerie + cr\u00e9ances + stocks + autres actifs < 1 an \u00b7 Passifs courants = dettes < 1 an \u00e0 rembourser</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Interpr\u00e9tation</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Un ratio inf\u00e9rieur \u00e0 <strong style=\"color:var(--ink)\">1\u00d7</strong> signifie que les dettes \u00e0 court terme exc\u00e8dent les actifs liquides disponibles \u2014 situation th\u00e9oriquement pr\u00e9occupante. Un ratio entre <strong style=\"color:var(--ink)\">1,5\u00d7 et 2\u00d7</strong> est g\u00e9n\u00e9ralement consid\u00e9r\u00e9 comme sain. Au-del\u00e0 de <strong style=\"color:var(--ink)\">3\u00d7</strong>, l'entreprise sur-immobilise du capital dans des actifs courants peu productifs.</p>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">< 1,0\u00d7</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--rose)\">Risque de liquidit\u00e9</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Vigilance requise</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">1,5 \u2013 2,0\u00d7</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">Zone de confort</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">\u00c9quilibre sain</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">> 3,0\u00d7</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">Capital mal utilis\u00e9</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Sur-stockage potentiel</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les limites importantes</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le Current Ratio inclut les stocks dans les actifs courants \u2014 or les stocks peuvent \u00eatre difficiles \u00e0 liquider rapidement (imaginez un fabricant automobile essayant de vendre ses pi\u00e8ces d'un coup). C'est pourquoi il existe une version plus stricte : le Quick Ratio, qui exclut les stocks.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Par ailleurs, certains mod\u00e8les \u00e9conomiques sains fonctionnent avec un Current Ratio inf\u00e9rieur \u00e0 1 : la grande distribution (Amazon, Carrefour) paie ses fournisseurs en 60-90 jours et encaisse imm\u00e9diatement ses clients \u2014 le ratio peut \u00eatre \u00e0 0,8\u00d7 sans aucun probl\u00e8me de liquidit\u00e9.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le Current Ratio mesure la couverture des dettes court terme par les actifs liquides. Un ratio de 1,5-2\u00d7 est g\u00e9n\u00e9ralement sain, mais l'interpr\u00e9tation d\u00e9pend fortement du secteur. Toujours analyser la composition des actifs courants \u2014 des stocks peu liquides peuvent masquer un vrai probl\u00e8me de liquidit\u00e9.</p>\n</div>\n",
  39: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Sant\u00e9 financi\u00e8re</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Quick Ratio \u2014 La liquidit\u00e9 sans filet</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le Quick Ratio (ou ratio de liquidit\u00e9 imm\u00e9diate) est la version s\u00e9v\u00e8re du Current Ratio. En excluant les stocks \u2014 souvent l'actif courant le moins liquide \u2014 il pose la vraie question de survie \u00e0 court terme : <strong style=\"color:var(--ink)\">si l'entreprise ne vend plus rien demain, peut-elle quand m\u00eame honorer ses dettes imm\u00e9diates ?</strong></p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Quick Ratio = (Tr\u00e9sorerie + Cr\u00e9ances clients) / Passifs courants</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">On peut aussi \u00e9crire : Quick Ratio = (Actifs courants \u2212 Stocks) / Passifs courants</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Quand le Quick Ratio est-il crucial ?</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le Quick Ratio est particuli\u00e8rement important pour les entreprises avec des stocks importants et potentiellement invendables en urgence : distributeurs, d\u00e9taillants de mode, fabricants industriels. Pour une entreprise de services ou de logiciel (sans stocks), Current Ratio et Quick Ratio sont quasiment identiques.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">Quick Ratio sain (>1\u00d7)</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Liquidit\u00e9s abondantes</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Tr\u00e9sorerie ou cr\u00e9ances couvrent les dettes</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">D\u00e9lais clients courts</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Encaissements rapides</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Peu de stocks</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Actifs courants d\u00e9j\u00e0 liquides</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:10px\">Quick Ratio pr\u00e9occupant (<0,7\u00d7)</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Stocks importants</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Seule ressource si les ventes s'arr\u00eatent</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Cr\u00e9ances longues</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">B2B avec d\u00e9lais 90-120 jours</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Secteurs cycliques</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Risque en bas de cycle</span></div>\n    </div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Quick Ratio vs Current Ratio : l'\u00e9cart r\u00e9v\u00e9lateur</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La comparaison des deux ratios est elle-m\u00eame informative. Un Current Ratio de 2\u00d7 mais un Quick Ratio de 0,6\u00d7 signifie que les actifs courants sont majoritairement compos\u00e9s de stocks. Cela ne pose pas de probl\u00e8me si les stocks sont facilement vendables (mati\u00e8res premi\u00e8res cot\u00e9es), mais devient pr\u00e9occupant pour des stocks de produits finis sp\u00e9cifiques ou saisonniers.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le Quick Ratio exclut les stocks pour mesurer la vraie liquidit\u00e9 imm\u00e9diate. Un ratio >1\u00d7 est g\u00e9n\u00e9ralement sain. L'\u00e9cart entre Quick Ratio et Current Ratio r\u00e9v\u00e8le l'importance des stocks dans les actifs courants \u2014 une information critique pour les entreprises \u00e0 fort inventaire.</p>\n</div>\n",
  40: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Sant\u00e9 financi\u00e8re</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Tr\u00e9sorerie Nette \u2014 Le matelas de s\u00e9curit\u00e9 absolu</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Si la tr\u00e9sorerie nette positive est l'indicateur de solidit\u00e9 financi\u00e8re le plus simple et le plus concret, c'est parce qu'elle r\u00e9pond \u00e0 une question binaire : l'entreprise a-t-elle plus de cash que de dettes financi\u00e8res ? Une tr\u00e9sorerie nette positive signifie que m\u00eame en remboursant toutes ses dettes aujourd'hui, il resterait de l'argent.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Tr\u00e9sorerie nette = Tr\u00e9sorerie et \u00e9quivalents \u2212 Dette financi\u00e8re totale</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Une valeur positive = 'net cash' \u00b7 Une valeur n\u00e9gative = 'net debt' (dette nette)</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'impact sur la valorisation</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La tr\u00e9sorerie nette est directement d\u00e9duite de l'EV : EV = Capitalisation \u2212 Tr\u00e9sorerie nette. Une entreprise cot\u00e9e \u00e0 1 Md\u20ac avec 300 M\u20ac de tr\u00e9sorerie nette a une valeur d'entreprise de seulement 700 M\u20ac. Si vous l'achetez int\u00e9gralement, vous r\u00e9cup\u00e9rez imm\u00e9diatement 300 M\u20ac dans la caisse \u2014 vous ne payez l'activit\u00e9 que 700 M\u20ac.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">Avantages d'une forte tr\u00e9sorerie nette</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">R\u00e9sistance aux chocs</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Peut traverser une r\u00e9cession sans lever de fonds</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Opportunit\u00e9s de croissance</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Finance acquisitions ou investissements sans dilution</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Retours aux actionnaires</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Rachats d'actions ou dividendes exceptionnels</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:10px\">Risques d'une tr\u00e9sorerie nette trop \u00e9lev\u00e9e</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Capital dormant</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Cash non investi ne cr\u00e9e pas de valeur</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Mauvaises acquisitions</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Tentations de d\u00e9penser imprudemment</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Cible de raiders</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Attrait pour les fonds activistes</span></div>\n    </div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les champions de la tr\u00e9sorerie nette</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Apple, Microsoft, Alphabet maintiennent des positions de tr\u00e9sorerie nette positives de plusieurs centaines de milliards de dollars. Cette tr\u00e9sorerie repr\u00e9sente \u00e0 la fois une assurance strat\u00e9gique et une flexibilit\u00e9 pour financer des acquisitions transformatrices ou des programmes de rachat massifs \u2014 sans avoir \u00e0 passer par les march\u00e9s financiers.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">La tr\u00e9sorerie nette (cash \u2212 dettes) est l'indicateur le plus direct de la solidit\u00e9 financi\u00e8re. Positive, elle offre flexibilit\u00e9 et r\u00e9silience. Elle se d\u00e9duit directement de la capitalisation boursi\u00e8re pour obtenir la valeur d'entreprise r\u00e9elle. Trop \u00e9lev\u00e9e, elle peut signaler un manque d'opportunit\u00e9s d'investissement rentables.</p>\n</div>\n",
  41: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Sant\u00e9 financi\u00e8re</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Z-Score d'Altman \u2014 Pr\u00e9dire la faillite avant qu'elle arrive</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 7 min \u00b7 Niveau : Avanc\u00e9</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">En 1968, Edward Altman, professeur de finance \u00e0 New York University, publie une \u00e9tude qui va r\u00e9volutionner l'analyse du risque de cr\u00e9dit. En combinant cinq ratios financiers dans une \u00e9quation unique, il pr\u00e9dit la faillite d'entreprises avec une pr\u00e9cision de 95 % sur 1 an et 72 % sur 2 ans. Son <strong style=\"color:var(--ink)\">Z-Score</strong> reste aujourd'hui l'un des mod\u00e8les les plus cit\u00e9s en finance.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Z = 1,2\u00b7X\u2081 + 1,4\u00b7X\u2082 + 3,3\u00b7X\u2083 + 0,6\u00b7X\u2084 + 1,0\u00b7X\u2085</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Formule pour entreprises manufacturi\u00e8res cot\u00e9es (version classique de 1968)</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les cinq ratios du Z-Score</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\"><strong style=\"color:var(--ink)\">X\u2081 = BFR / Total actifs</strong> \u2014 Mesure la liquidit\u00e9 relative. Un BFR n\u00e9gatif ou tr\u00e8s faible p\u00e9nalise le score.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\"><strong style=\"color:var(--ink)\">X\u2082 = R\u00e9serves / Total actifs</strong> \u2014 Accumulation de b\u00e9n\u00e9fices dans le temps (levier de la profitabilit\u00e9 historique).</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\"><strong style=\"color:var(--ink)\">X\u2083 = EBIT / Total actifs</strong> \u2014 Rentabilit\u00e9 de l'actif op\u00e9rationnel.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\"><strong style=\"color:var(--ink)\">X\u2084 = Capitalisation boursi\u00e8re / Dettes totales</strong> \u2014 Capacit\u00e9 \u00e0 absorber des pertes avant insolvabilit\u00e9.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\"><strong style=\"color:var(--ink)\">X\u2085 = CA / Total actifs</strong> \u2014 Rotation des actifs (efficacit\u00e9 commerciale).</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Interpr\u00e9tation du score</h2>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Z > 2,99</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">Zone s\u00fbre</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Faible probabilit\u00e9 de faillite</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">1,81 < Z < 2,99</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">Zone grise</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Situation \u00e0 surveiller</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Z < 1,81</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--rose)\">Zone de d\u00e9tresse</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Risque \u00e9lev\u00e9 de faillite</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Limites et \u00e9volutions du mod\u00e8le</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Altman a lui-m\u00eame d\u00e9velopp\u00e9 plusieurs versions adapt\u00e9es : le Z'-Score pour les entreprises non cot\u00e9es (remplace la capitalisation par les capitaux propres comptables), le Z''-Score pour les entreprises de services et les march\u00e9s \u00e9mergents. Ces adaptations reconnaissent que le mod\u00e8le original, calibr\u00e9 sur des manufacturiers am\u00e9ricains des ann\u00e9es 60, ne s'applique pas universellement.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:8px\">Ne pas utiliser m\u00e9caniquement</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Un Z-Score faible n'est pas une certitude de faillite : les entreprises en restructuration, les conglom\u00e9rats et les groupes financiers ont des structures bilancielles qui faussent les r\u00e9sultats. Le Z-Score est un signal d'alerte, pas une condamnation.</p>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le Z-Score d'Altman combine 5 ratios en un indicateur unique de risque de faillite. Un score < 1,81 indique une zone de d\u00e9tresse financi\u00e8re m\u00e9ritant une analyse approfondie. Malgr\u00e9 ses 50 ans, il reste un outil de screening efficace et un compl\u00e9ment utile aux analyses de cr\u00e9dit traditionnelles.</p>\n</div>\n",
  42: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Dividendes</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Les Dividend Aristocrats \u2014 L'\u00e9lite des payeurs de dividendes</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Parmi les milliers d'entreprises cot\u00e9es, une centaine seulement m\u00e9ritent le titre de <strong style=\"color:var(--ink)\">Dividend Aristocrat</strong> : des entreprises qui ont augment\u00e9 leur dividende chaque ann\u00e9e pendant au moins 25 ann\u00e9es cons\u00e9cutives. Ce palmar\u00e8s, souvent qualifi\u00e9 de Saint-Graal pour les investisseurs de revenu, r\u00e9v\u00e8le bien plus qu'une simple g\u00e9n\u00e9rosit\u00e9 envers les actionnaires.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les crit\u00e8res officiels (S&P 500 Dividend Aristocrats Index)</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Pour int\u00e9grer l'indice S&P 500 Dividend Aristocrats, une entreprise doit : \u00eatre membre du S&P 500, avoir augment\u00e9 (ou maintenu) son dividende pendant 25 ann\u00e9es cons\u00e9cutives minimum, et respecter des crit\u00e8res de liquidit\u00e9 minimum. En 2024, environ 65 entreprises satisfaisaient ces crit\u00e8res.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">Secteurs surrepr\u00e9sent\u00e9s</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Biens de consommation</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Procter & Gamble, Colgate, Coca-Cola</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Sant\u00e9 / Pharma</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Johnson & Johnson, Abbott</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Industrie</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">3M, Emerson Electric, Cintas</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--blue);margin-bottom:10px\">Ce que la dur\u00e9e r\u00e9v\u00e8le</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Business model r\u00e9silient</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Survit aux cycles \u00e9conomiques</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">G\u00e9n\u00e9ration de cash fiable</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Dividende = engagement dur \u00e0 tenir</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Gestion disciplin\u00e9e</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">\u00c9vite les exc\u00e8s d'investissement</span></div>\n    </div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Performance historique</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Sur longue p\u00e9riode, les Dividend Aristocrats ont surperform\u00e9 le S&P 500 avec une volatilit\u00e9 inf\u00e9rieure \u2014 la combinaison r\u00eav\u00e9e risque/rendement. Leur r\u00e9silience lors des crises (2008, 2020) s'explique : une entreprise qui coupe son dividende apr\u00e8s 25 ans de hausses enverrait un signal catastrophique aux march\u00e9s \u2014 les dirigeants font donc tout pour pr\u00e9server cette s\u00e9rie.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:8px\">Attention \u00e0 la chasse au rendement</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Un dividende \u00e9lev\u00e9 combin\u00e9 \u00e0 une longue dur\u00e9e de versement n'est pas un signal automatique d'achat. Une entreprise dont le cours baisse structurellement affichera un rendement croissant \u2014 m\u00e9caniquement, pas parce qu'elle est g\u00e9n\u00e9reuse. V\u00e9rifiez toujours la soutenabilit\u00e9 du dividende via le payout ratio et le free cash flow.</p>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Les Dividend Aristocrats sont des entreprises qui ont augment\u00e9 leur dividende pendant 25+ ann\u00e9es cons\u00e9cutives \u2014 une prouesse qui n\u00e9cessite un mod\u00e8le \u00e9conomique robuste, une g\u00e9n\u00e9ration de cash r\u00e9guli\u00e8re et une discipline financi\u00e8re exemplaire. Ils constituent une base solide pour les portefeuilles ax\u00e9s sur le revenu \u00e0 long terme.</p>\n</div>\n",
  43: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Dividendes</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Croissance du Dividende (CAGR) \u2014 Le rendement futur cach\u00e9</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Un rendement de dividende de 1,5 % peut sembler d\u00e9risoire par rapport aux 4 % d'une obligation. Mais si ce dividende cro\u00eet de 10 % par an, dans 10 ans le rendement sur votre co\u00fbt d'achat initial sera de <strong style=\"color:var(--ink)\">~3,9 %</strong> \u2014 et dans 20 ans de ~10 %. C'est la magie de la croissance du dividende, et la raison pour laquelle certains investisseurs pr\u00e9f\u00e8rent un faible rendement \u00e0 forte croissance \u00e0 un rendement \u00e9lev\u00e9 stagnant.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">CAGR dividende = (Dividende annuel N / Dividende annuel 0)^(1/N) \u2212 1</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">N = nombre d'ann\u00e9es \u00b7 Le CAGR lisse la croissance annuelle compos\u00e9e sur la p\u00e9riode</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le Yield on Cost : la vraie m\u00e9trique \u00e0 long terme</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le <strong style=\"color:var(--ink)\">Yield on Cost</strong> (rendement sur co\u00fbt) est le dividende actuel divis\u00e9 par votre prix d'achat initial. C'est la m\u00e9trique qui illustre le mieux la puissance de la croissance du dividende dans le temps. Un investisseur ayant achet\u00e9 Coca-Cola dans les ann\u00e9es 1980 \u00e0 1 $ a un Yield on Cost de plusieurs centaines de pour cent aujourd'hui.</p>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">CAGR 5 %</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">+63 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Doublement en ~15 ans</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">CAGR 10 %</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">+159 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Doublement en 7 ans</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">CAGR 15 %</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">+305 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Doublement en ~5 ans</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">CAGR du dividende vs rendement imm\u00e9diat : le bon arbitrage</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Il existe un arbitrage classique entre deux profils d'actions dividendes : les actions \u00e0 haut rendement statique (utilities, tabac : 4-7 % mais croissance lente) et les actions \u00e0 faible rendement mais forte croissance (tech, sant\u00e9 : 0,5-2 % mais 8-15 % de CAGR). Pour un horizon de 10 ans+, les secondes surperforment g\u00e9n\u00e9ralement.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">La croissance du dividende (CAGR) est souvent plus importante que le rendement imm\u00e9diat pour un investisseur \u00e0 long terme. Un dividende qui cro\u00eet r\u00e9guli\u00e8rement \u00e0 8-12 % par an d\u00e9passe en 10-15 ans le rendement d'une action \u00e0 dividende \u00e9lev\u00e9 mais stagnant. Le Yield on Cost devient le vrai indicateur de performance.</p>\n</div>\n",
  44: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Dividendes</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le DRIP \u2014 Les dividendes qui s'investissent eux-m\u00eames</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le DRIP (Dividend Reinvestment Plan) est une m\u00e9canique simple mais d'une puissance redoutable sur le long terme : plut\u00f4t que de percevoir son dividende en esp\u00e8ces, l'investisseur l'utilise automatiquement pour acheter de nouvelles actions de la m\u00eame entreprise. C'est l'incarnation pratique de l'int\u00e9r\u00eat compos\u00e9 appliqu\u00e9 \u00e0 l'investissement en actions.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Comment fonctionne le DRIP ?</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">\u00c0 chaque date de versement du dividende, au lieu de cr\u00e9diter du cash sur le compte de l'investisseur, le courtier ou l'entreprise ach\u00e8te automatiquement des fractions d'actions suppl\u00e9mentaires. Ces nouvelles actions g\u00e9n\u00e8rent \u00e0 leur tour des dividendes, qui ach\u00e8tent \u00e0 leur tour plus d'actions \u2014 et ainsi de suite.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Valeur finale = Valeur initiale \u00d7 (1 + rendement total)^N</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Le 'rendement total' inclut la performance du cours ET les dividendes r\u00e9investis</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'impact chiffr\u00e9 : simulation sur 30 ans</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Pour 10 000 \u20ac investis dans une action avec un cours qui cro\u00eet de 7 % par an et un dividende de 3 % r\u00e9investi : sans DRIP (dividendes en cash) \u2192 ~76 000 \u20ac. Avec DRIP (dividendes r\u00e9investis) \u2192 ~132 000 \u20ac. L'\u00e9cart repr\u00e9sente <strong style=\"color:var(--ink)\">+74 %</strong> de valeur finale, simplement gr\u00e2ce au r\u00e9investissement automatique.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">Avantages du DRIP</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Effet boule de neige</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Chaque action suppl\u00e9mentaire g\u00e9n\u00e8re plus de dividendes</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Discipline automatique</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">\u00c9limine la tentation de consommer les dividendes</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Dollar-cost averaging</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Ach\u00e8te plus d'actions quand le cours est bas</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:10px\">Limites \u00e0 consid\u00e9rer</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Fiscalit\u00e9 imm\u00e9diate</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Le dividende r\u00e9investi est imposable comme du cash</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Concentration</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Renforce automatiquement une seule position</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Fractions d'actions</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Pas toujours disponible selon le courtier</span></div>\n    </div>\n  </div>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le DRIP transforme chaque dividende en nouvel investissement automatique, amplifiant consid\u00e9rablement les rendements sur le long terme gr\u00e2ce \u00e0 l'effet des int\u00e9r\u00eats compos\u00e9s. Sur 20-30 ans, la diff\u00e9rence entre percevoir et r\u00e9investir les dividendes peut repr\u00e9senter 50-100 % de valeur finale suppl\u00e9mentaire.</p>\n</div>\n",
  45: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Risque</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Volatilit\u00e9 \u2014 Mesurer l'incertitude d'un actif</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La volatilit\u00e9 est la mesure de risque la plus universellement utilis\u00e9e en finance. Elle quantifie l'amplitude des fluctuations des rendements d'un actif autour de sa moyenne. Plus un actif est volatil, plus ses rendements quotidiens ou mensuels sont impr\u00e9visibles \u2014 et plus l'investisseur doit \u00eatre psychologiquement et financi\u00e8rement pr\u00e9par\u00e9 \u00e0 des \u00e9carts importants.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Volatilit\u00e9 (annualis\u00e9e) = \u00c9cart-type des rendements journaliers \u00d7 \u221a252</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">252 = nombre de jours de bourse dans une ann\u00e9e \u00b7 L'\u00e9cart-type mesure la dispersion autour de la moyenne</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Interpr\u00e9tation concr\u00e8te</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Une volatilit\u00e9 annualis\u00e9e de 20 % signifie, en simplifiant, que le rendement annuel de l'actif se situera dans l'intervalle [rendement moyen \u00b1 20 %] dans environ 68 % des cas (\u00e0 \u00b11 \u00e9cart-type), et dans [rendement moyen \u00b1 40 %] dans 95 % des cas. C'est l'intervalle de confiance pratique pour l'investisseur.</p>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Obligations d'\u00c9tat</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">2\u20138 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Risque minimal</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Actions large cap</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">15\u201325 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Risque mod\u00e9r\u00e9</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Crypto / Small caps</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--rose)\">50\u2013100 %+</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Risque \u00e9lev\u00e9</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Volatilit\u00e9 r\u00e9alis\u00e9e vs volatilit\u00e9 implicite</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La <strong style=\"color:var(--ink)\">volatilit\u00e9 r\u00e9alis\u00e9e</strong> est calcul\u00e9e a posteriori \u00e0 partir des donn\u00e9es historiques. La <strong style=\"color:var(--ink)\">volatilit\u00e9 implicite</strong> est extraite du prix des options \u2014 elle refl\u00e8te ce que le march\u00e9 anticipe comme volatilit\u00e9 future. L'indice VIX est la volatilit\u00e9 implicite \u00e0 30 jours du S&P 500 ; un VIX \u00e9lev\u00e9 (>30) signale la peur, un VIX bas (<15) la complaisance.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:8px\">Limite fondamentale</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">La volatilit\u00e9 pass\u00e9e n'est pas un pr\u00e9dicteur fiable de la volatilit\u00e9 future. Elle a tendance \u00e0 \u00eatre auto-corr\u00e9l\u00e9e (les p\u00e9riodes calmes restent calmes, les crises restent volatiles) mais les chocs soudains la rendent intrins\u00e8quement difficile \u00e0 pr\u00e9dire.</p>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">La volatilit\u00e9 annualis\u00e9e mesure la dispersion des rendements d'un actif. C'est le d\u00e9nominateur du ratio de Sharpe et le principal param\u00e8tre des mod\u00e8les d'options. Elle est sym\u00e9trique \u2014 elle mesure les hausses ET les baisses \u2014 ce qui explique pourquoi certains pr\u00e9f\u00e8rent le downside risk (ratio de Sortino) pour \u00e9valuer le risque r\u00e9el d'un portefeuille.</p>\n</div>\n",
  46: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Risque</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Corr\u00e9lation \u2014 La cl\u00e9 de la diversification efficace</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La corr\u00e9lation est le principe fondateur de la th\u00e9orie moderne du portefeuille de Markowitz. Elle explique pourquoi deux actifs risqu\u00e9s combin\u00e9s peuvent former un portefeuille moins risqu\u00e9 que chacun pris s\u00e9par\u00e9ment. Comprendre la corr\u00e9lation, c'est comprendre pourquoi la diversification fonctionne \u2014 et pourquoi elle peut \u00e9chouer.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Corr\u00e9lation (\u03c1) = Cov(A, B) / (\u03c3A \u00d7 \u03c3B)</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Coefficient de Pearson, toujours compris entre \u22121 et +1 \u00b7 Cov = covariance des rendements \u00b7 \u03c3 = \u00e9cart-type (volatilit\u00e9)</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'\u00e9chelle de corr\u00e9lation</h2>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u03c1 = +1,0</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--rose)\">Corr\u00e9lation parfaite</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Se d\u00e9placent ensemble \u2014 z\u00e9ro b\u00e9n\u00e9fice de diversification</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u03c1 = 0,0</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">Ind\u00e9pendance</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Diversification maximale atteignable</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u03c1 = \u22121,0</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">Anti-corr\u00e9lation parfaite</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Couverture parfaite \u2014 risque nul en combinaison</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Corr\u00e9lation et diversification du portefeuille</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Pour deux actifs A et B de volatilit\u00e9s \u03c3A et \u03c3B, la volatilit\u00e9 d'un portefeuille compos\u00e9 \u00e0 50/50 diminue \u00e0 mesure que \u03c1 diminue. En passant de \u03c1=1 \u00e0 \u03c1=0, on r\u00e9alise d'importants gains de diversification. En passant \u00e0 \u03c1 n\u00e9gatif, on peut r\u00e9duire la volatilit\u00e9 bien en dessous de celle du moins risqu\u00e9 des deux actifs.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les corr\u00e9lations ne sont pas stables</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le pi\u00e8ge majeur : <strong style=\"color:var(--ink)\">les corr\u00e9lations augmentent massivement en p\u00e9riode de crise</strong>. En 2008, des actifs cens\u00e9s \u00eatre d\u00e9corr\u00e9l\u00e9s (actions europ\u00e9ennes et am\u00e9ricaines, obligations d'entreprises, immobilier) ont chut\u00e9 ensemble. La diversification dispara\u00eet pr\u00e9cis\u00e9ment quand on en a le plus besoin \u2014 ph\u00e9nom\u00e8ne de corr\u00e9lation conditionnelle.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:8px\">Diversification illusoire</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Poss\u00e9der 50 actions du m\u00eame secteur, ou 20 ETF qui investissent tous dans le S&P 500, ne constitue pas une vraie diversification. Les corr\u00e9lations intra-sectorielles ou intra-march\u00e9 sont tr\u00e8s \u00e9lev\u00e9es. La vraie diversification n\u00e9cessite des classes d'actifs, g\u00e9ographies et facteurs vraiment diff\u00e9rents.</p>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">La corr\u00e9lation mesure le degr\u00e9 de co-mouvement entre deux actifs. Des corr\u00e9lations faibles ou n\u00e9gatives permettent de construire des portefeuilles mieux diversifi\u00e9s (fronti\u00e8re efficiente). Attention : les corr\u00e9lations ne sont pas stables et tendent \u00e0 converger vers 1 lors des crises, r\u00e9duisant les b\u00e9n\u00e9fices de la diversification au moment le plus critique.</p>\n</div>\n",
  47: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Risque</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Maximum Drawdown \u2014 La pire chute que vous aurez \u00e0 supporter</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La volatilit\u00e9 mesure l'amplitude des fluctuations quotidiennes. Mais pour un investisseur, la vraie question pratique est diff\u00e9rente : <strong style=\"color:var(--ink)\">quelle est la pire perte que j'aurais pu subir si j'avais investi au plus mauvais moment ?</strong> C'est ce que mesure le Maximum Drawdown (MDD) \u2014 la baisse maximale d'un pic \u00e0 un creux sur une p\u00e9riode donn\u00e9e.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">MDD = (Creux \u2212 Pic pr\u00e9c\u00e9dent) / Pic pr\u00e9c\u00e9dent \u00d7 100</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">On cherche la paire (pic, creux) qui maximise la perte en pourcentage \u00b7 Toujours exprim\u00e9 en valeur n\u00e9gative</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Exemples historiques marquants</h2>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">S&P 500 \u2014 2008</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--rose)\">\u221256 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">De oct. 2007 \u00e0 mars 2009</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Nasdaq \u2014 2000</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--rose)\">\u221278 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Crise dot-com, 2 ans et demi</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Bitcoin \u2014 2022</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">\u221277 %</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">De 69k$ \u00e0 15,5k$</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">MDD et psychologie de l'investisseur</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le MDD est une m\u00e9trique profond\u00e9ment <em>humaine</em>. Un portefeuille qui chute de 50 % doit ensuite gagner <strong style=\"color:var(--ink)\">+100 %</strong> pour retrouver son niveau d'origine \u2014 pas simplement +50 %. C'est l'asym\u00e9trie des pertes. Un investisseur qui ne peut psychologiquement ni financi\u00e8rement supporter un drawdown de 40 % doit calibrer son portefeuille en cons\u00e9quence, ind\u00e9pendamment de la volatilit\u00e9 th\u00e9orique.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Drawdown et temps de r\u00e9cup\u00e9ration</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Deux m\u00e9triques compl\u00e9mentaires : le MDD absolu et la <strong style=\"color:var(--ink)\">dur\u00e9e de r\u00e9cup\u00e9ration</strong> (temps pour revenir au pr\u00e9c\u00e9dent pic). Une perte de 20 % r\u00e9cup\u00e9r\u00e9e en 6 mois est tr\u00e8s diff\u00e9rente d'une perte de 20 % r\u00e9cup\u00e9r\u00e9e en 5 ans (comme certaines valeurs technologiques apr\u00e8s 2000).</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le Maximum Drawdown est la mesure de risque la plus parlante pour l'investisseur r\u00e9el : elle illustre la pire perte historique qu'il aurait support\u00e9e. Un MDD acceptable d\u00e9pend de l'horizon d'investissement et de la capacit\u00e9 psychologique et financi\u00e8re \u00e0 supporter des pertes temporaires sans paniquer et vendre au plus bas.</p>\n</div>\n",
  48: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Risque</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Ratio de Sortino \u2014 Ne punir que le mauvais risque</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le ratio de Sharpe divise le rendement exc\u00e9dentaire par la volatilit\u00e9 totale. Mais cette approche p\u00e9nalise \u00e9galement les hausses impr\u00e9vues \u2014 or les investisseurs ne se plaignent pas quand le march\u00e9 monte plus que pr\u00e9vu. Le <strong style=\"color:var(--ink)\">ratio de Sortino</strong>, d\u00e9velopp\u00e9 par Frank Sortino, corrige cette asym\u00e9trie : il ne mesure que la volatilit\u00e9 des rendements n\u00e9gatifs.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Ratio de Sortino = (Rendement \u2212 Taux cible) / Volatilit\u00e9 baissi\u00e8re</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Volatilit\u00e9 baissi\u00e8re (downside deviation) = \u00e9cart-type calcul\u00e9 uniquement sur les rendements inf\u00e9rieurs au taux cible</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Downside deviation : le calcul</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Pour calculer la volatilit\u00e9 baissi\u00e8re, on proc\u00e8de ainsi : on identifie tous les rendements inf\u00e9rieurs au taux cible (souvent le taux sans risque ou 0 %), on calcule pour chacun le carr\u00e9 de l'\u00e9cart au taux cible, on fait la moyenne, puis la racine carr\u00e9e. Les rendements sup\u00e9rieurs au taux cible contribuent pour 0 \u2014 ils ne sont pas p\u00e9nalis\u00e9s.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Sortino vs Sharpe : quand divergent-ils ?</h2>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">Sortino > Sharpe (normalis\u00e9)</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Distribution asym\u00e9trique positive</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Plus de hausses que de baisses</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Strat\u00e9gies optionnelles</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Vente de put, structures \u00e0 capital garanti</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Value / Momentum</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Rendements asym\u00e9triques fr\u00e9quents</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--blue);margin-bottom:10px\">Sortino \u2248 Sharpe</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Distribution normale</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Pertes et gains \u00e9galement distribu\u00e9s</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">ETF indiciels</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Portefeuille march\u00e9 bien diversifi\u00e9</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Long-only passif</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Peu d'asym\u00e9trie structurelle</span></div>\n    </div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Interpr\u00e9tation pratique</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Un ratio de Sortino sup\u00e9rieur \u00e0 <strong style=\"color:var(--ink)\">1,0</strong> est g\u00e9n\u00e9ralement consid\u00e9r\u00e9 comme bon. Sup\u00e9rieur \u00e0 2,0 est excellent. Un portefeuille avec un Sortino de 1,5 et un Sharpe de 0,8 est typiquement une strat\u00e9gie qui a peu de pertes importantes mais des hausses fr\u00e9quentes \u2014 un profil id\u00e9al pour beaucoup d'investisseurs.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le ratio de Sortino am\u00e9liore le Sharpe en ne p\u00e9nalisant que les rendements inf\u00e9rieurs au taux cible. Il est particuli\u00e8rement pertinent pour les strat\u00e9gies \u00e0 asym\u00e9trie positive et les investisseurs soucieux du risque de baisse plut\u00f4t que de la volatilit\u00e9 totale. Un Sortino > 1 est bon ; > 2 est excellent.</p>\n</div>\n",
  49: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Risque</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">L'Alpha de Jensen \u2014 La surperformance ajust\u00e9e au risque</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Tous les fonds qui battent leur indice de r\u00e9f\u00e9rence ne m\u00e9ritent pas d'\u00eatre f\u00e9licit\u00e9s. Certains le font simplement en prenant plus de risque que l'indice. L'<strong style=\"color:var(--ink)\">alpha de Jensen</strong>, d\u00e9velopp\u00e9 par Michael Jensen en 1968, mesure la surperformance r\u00e9elle d'un portefeuille une fois \u00e9limin\u00e9 l'effet m\u00e9canique de son exposition au march\u00e9 (b\u00eata).</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">\u03b1 = Rp \u2212 [Rf + \u03b2 \u00d7 (Rm \u2212 Rf)]</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Rp = rendement du portefeuille \u00b7 Rf = taux sans risque \u00b7 \u03b2 = b\u00eata du portefeuille \u00b7 Rm = rendement du march\u00e9</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Interpr\u00e9tation de l'alpha</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Si un fonds g\u00e9n\u00e8re 12 % de rendement avec un b\u00eata de 1,3, un march\u00e9 \u00e0 8 % et un taux sans risque \u00e0 3 %, le rendement attendu par le MEDAF est : 3 % + 1,3 \u00d7 (8% \u2212 3%) = 9,5 %. L'alpha est donc 12 % \u2212 9,5 % = <strong style=\"color:var(--ink)\">+2,5 %</strong>. Le gestionnaire a ajout\u00e9 2,5 % de valeur au-del\u00e0 de ce que son exposition au march\u00e9 explique m\u00e9caniquement.</p>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u03b1 > 0</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">Surperformance</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Comp\u00e9tence ou information</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u03b1 = 0</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--blue)\">Performance neutre</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Aucune valeur ajout\u00e9e</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u03b1 < 0</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--rose)\">Sous-performance</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Frais non compens\u00e9s</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'alpha est-il persistant ?</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La recherche acad\u00e9mique montre que l'alpha positif est difficile \u00e0 maintenir dans le temps. Apr\u00e8s d\u00e9duction des frais de gestion, environ 80-90 % des fonds actifs sous-performent leur indice sur 15 ans. Les quelques gestionnaires qui g\u00e9n\u00e8rent un alpha positif persistant (Buffett, Lynch, Lynch-style value) sont de rares exceptions que les biais de survie rendent difficiles \u00e0 distinguer de la chance.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">L'alpha de Jensen mesure la performance pure du gestionnaire, nettoy\u00e9e de l'effet m\u00e9canique de l'exposition au march\u00e9. Un alpha positif signifie que le g\u00e9rant a cr\u00e9\u00e9 de la valeur au-del\u00e0 de ce que son niveau de risque syst\u00e9matique explique. La difficult\u00e9 \u00e0 g\u00e9n\u00e9rer un alpha persistant justifie l'investissement passif pour la plupart des investisseurs.</p>\n</div>\n",
  50: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Risque</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Value at Risk (VaR) \u2014 La perte maximale probable</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 7 min \u00b7 Niveau : Avanc\u00e9</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La Value at Risk (VaR) est la mesure de risque de r\u00e9f\u00e9rence des banques, des fonds sp\u00e9culatifs et des r\u00e9gulateurs financiers depuis les ann\u00e9es 1990. Elle r\u00e9pond \u00e0 une question pr\u00e9cise : <strong style=\"color:var(--ink)\">quelle est la perte maximale que je peux subir avec X % de probabilit\u00e9 sur une p\u00e9riode donn\u00e9e ?</strong></p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">VaR(\u03b1, T) = \u2212Rendement minimum pour un niveau de confiance \u03b1 sur T jours</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : VaR(95 %, 1 jour) = 2 % signifie une perte maximale de 2 % le lendemain dans 95 % des cas</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Trois m\u00e9thodes de calcul</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\"><strong style=\"color:var(--ink)\">VaR historique</strong> : On ordonne les rendements pass\u00e9s et on prend le percentile correspondant au niveau de confiance. Simple mais tributaire de la p\u00e9riode historique choisie.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\"><strong style=\"color:var(--ink)\">VaR param\u00e9trique (variance-covariance)</strong> : On suppose une distribution normale et on utilise la formule z \u00d7 \u03c3 \u00d7 \u221aT. Rapide mais peu pr\u00e9cise pour les distributions avec queues \u00e9paisses.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\"><strong style=\"color:var(--ink)\">VaR Monte Carlo</strong> : On simule des milliers de sc\u00e9narios de march\u00e9s via des processus stochastiques. Tr\u00e8s flexible mais computationnellement intensive.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La limite majeure : ce qui se passe au-del\u00e0 de la VaR</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La VaR \u00e0 95 % dit ce qui se passe 95 % du temps. Mais elle ne dit rien sur l'amplitude des pertes dans les 5 % restants. C'est pourquoi la <strong style=\"color:var(--ink)\">CVaR</strong> (Conditional VaR ou Expected Shortfall) a \u00e9t\u00e9 d\u00e9velopp\u00e9e : elle mesure la perte <em>moyenne</em> dans le sc\u00e9nario de d\u00e9passement de la VaR, capturant mieux les risques de queue.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:8px\">Les limites r\u00e9v\u00e9l\u00e9es par 2008</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Les mod\u00e8les VaR des grandes banques en 2008 avaient drastiquement sous-estim\u00e9 les risques de queue car calibr\u00e9s sur des donn\u00e9es r\u00e9centes sans crise majeure. Les distributions de rendements financiers ont des 'queues \u00e9paisses' (fat tails) que la distribution normale sous-estime. C'est pourquoi le stress testing est compl\u00e9mentaire de la VaR.</p>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">La VaR quantifie la perte maximale probable \u00e0 un niveau de confiance et une p\u00e9riode donn\u00e9s. C'est la mesure r\u00e9glementaire standard pour les banques (B\u00e2le III). Elle doit \u00eatre compl\u00e9t\u00e9e par la CVaR (pour les sc\u00e9narios extr\u00eames) et des stress tests (pour les chocs non mod\u00e9lis\u00e9s). La VaR seule est insuffisante pour g\u00e9rer le risque de queue.</p>\n</div>\n",
  51: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Risque</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Tracking Error & Information Ratio \u2014 Mesurer la gestion active</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 6 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Deux indicateurs incontournables pour \u00e9valuer un fonds g\u00e9r\u00e9 activement : le <strong style=\"color:var(--ink)\">Tracking Error</strong>, qui mesure l'\u00e9cart de comportement par rapport \u00e0 l'indice, et l'<strong style=\"color:var(--ink)\">Information Ratio</strong>, qui \u00e9value si cet \u00e9cart est r\u00e9compens\u00e9. Ensemble, ils d\u00e9terminent la qualit\u00e9 de la gestion active.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Tracking Error (TE) = \u00c9cart-type (Rp \u2212 Rb)</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Rp = rendement du portefeuille \u00b7 Rb = rendement du benchmark \u00b7 Calcul\u00e9 sur rendements p\u00e9riodiques (journaliers ou mensuels)</div>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Information Ratio (IR) = (Rp \u2212 Rb) / Tracking Error</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">= Surperformance annualis\u00e9e / Tracking Error annualis\u00e9 \u00b7 L'\u00e9quivalent du Sharpe appliqu\u00e9 \u00e0 l'alpha</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Interpr\u00e9tation du Tracking Error</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Un TE faible (< 2 %) signifie que le fonds colle \u00e9troitement \u00e0 son indice \u2014 c'est un fonds 'closet indexer', qui facture des frais actifs pour un comportement quasi-passif. Un TE \u00e9lev\u00e9 (> 8 %) indique que le g\u00e9rant s'\u00e9loigne significativement de son indice, pour le meilleur ou pour le pire.</p>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">TE < 2 %</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--rose)\">Fonds armoire</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Gestion active factur\u00e9e, passive en pratique</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">TE 3\u20137 %</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--teal)\">Gestion active mod\u00e9r\u00e9e</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Conviction mesur\u00e9e</div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">TE > 10 %</div>\n    <div style=\"font-family:var(--font-serif);font-size:1.5rem;font-weight:700;color:var(--amber)\">High conviction</div>\n    <div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Forte d\u00e9viation \u2014 risque et opportunit\u00e9</div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'Information Ratio : le test de comp\u00e9tence</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">L'IR > 0,5 est consid\u00e9r\u00e9 comme bon, > 1,0 comme excellent dans l'industrie. Mais sa vraie valeur est sa persistance : un IR positif sur 1 an peut \u00eatre de la chance ; positif sur 5-10 ans commence \u00e0 ressembler \u00e0 de la comp\u00e9tence. Les \u00e9tudes montrent qu'un IR positif persistant est extr\u00eamement rare parmi les g\u00e9rants actifs.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le Tracking Error mesure l'\u00e9cart de comportement d'un fonds par rapport \u00e0 son indice ; l'Information Ratio mesure si cet \u00e9cart est efficacement r\u00e9mun\u00e9r\u00e9. Un IR > 0,5 est bon. Ces indicateurs permettent de distinguer les g\u00e9rants actifs qui cr\u00e9ent vraiment de la valeur des 'closet indexers' qui facturent des frais actifs pour des performances passives.</p>\n</div>\n",
  52: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Strat\u00e9gie</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Value Investing \u2014 Acheter \u00e0 rabais, attendre la juste valeur</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 6 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">N\u00e9 des travaux de Benjamin Graham dans les ann\u00e9es 1930, popularis\u00e9 par Warren Buffett, le <strong style=\"color:var(--ink)\">value investing</strong> est la strat\u00e9gie d'investissement la plus document\u00e9e et la plus \u00e9tudi\u00e9e de l'histoire financi\u00e8re. Son principe tient en une phrase : acheter des actifs en dessous de leur valeur intrins\u00e8que et attendre que le march\u00e9 reconnaisse cette valeur.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les fondements de Graham : Mr. Market et la marge de s\u00e9curit\u00e9</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Graham personnifie le march\u00e9 financier sous le nom de <strong style=\"color:var(--ink)\">Mr. Market</strong> \u2014 un partenaire commercial lunatique qui vous propose chaque jour de racheter ou de vous vendre votre part de l'entreprise. Parfois il est euphorique et propose un prix excessif ; parfois il est d\u00e9prim\u00e9 et propose un prix d\u00e9risoire. La sagesse consiste \u00e0 lui vendre quand il est euphorique et \u00e0 lui acheter quand il est d\u00e9prim\u00e9.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'\u00e9volution vers le 'Wonderful business at a fair price'</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Graham cherchait des 'cigar butts' \u2014 des entreprises si bon march\u00e9 qu'il restait 'une derni\u00e8re bouff\u00e9e' \u00e0 prendre. Buffett, sous l'influence de Charlie Munger, a \u00e9volu\u00e9 vers une version plus qualitative : payer un prix raisonnable pour une <strong style=\"color:var(--ink)\">entreprise extraordinaire</strong> \u2014 dot\u00e9e d'un avantage comp\u00e9titif durable, d'un bon management et d'une longue piste de croissance.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--blue);margin-bottom:10px\">Value classique (Graham)</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">P/B < 1\u00d7</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Actif \u00e0 moiti\u00e9 prix</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">P/E < 15\u00d7</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Profits bon march\u00e9</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Bilan solide</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Peu de dettes</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">Quality Value (Buffett)</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Moat \u00e9conomique</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Avantage concurrentiel durable</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">ROIC > 15 % persistant</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Vraie cr\u00e9ation de valeur</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Management align\u00e9</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Capital intelligemment allou\u00e9</span></div>\n    </div>\n  </div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le facteur value : persistance acad\u00e9mique</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Fama et French ont document\u00e9 que les actions 'value' (P/B faible) surperforment les actions 'growth' sur longue p\u00e9riode \u2014 c'est le <em>value premium</em>. Ce ph\u00e9nom\u00e8ne persiste depuis 1926 sur les march\u00e9s US, bien que les d\u00e9cennies 2010-2020 aient vu le growth significativement surperformer. La majorit\u00e9 des acad\u00e9miciens s'accordent sur le fait que ce premium compense un risque r\u00e9el (fragilit\u00e9 des entreprises value).</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le value investing consiste \u00e0 identifier des actifs dont le prix de march\u00e9 est inf\u00e9rieur \u00e0 la valeur intrins\u00e8que estim\u00e9e, puis \u00e0 attendre la convergence. Sa version moderne (quality value) recherche des entreprises exceptionnelles \u00e0 prix raisonnable. La patience et la discipline de ne pas suivre les modes de march\u00e9 sont ses exigences essentielles.</p>\n</div>\n",
  53: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Strat\u00e9gie</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le DCA \u2014 Investir r\u00e9guli\u00e8rement pour \u00e9liminer le timing</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le DCA (Dollar-Cost Averaging, ou investissement programm\u00e9) est la strat\u00e9gie d'investissement la plus accessible et la plus \u00e9prouv\u00e9e pour l'investisseur non professionnel. Son principe : investir une somme fixe \u00e0 intervalles r\u00e9guliers, ind\u00e9pendamment du niveau des march\u00e9s. Ce faisant, on ach\u00e8te automatiquement plus d'actions quand les cours sont bas et moins quand ils sont hauts.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n  <div style=\"font-family:Georgia,serif;font-size:1.35rem;color:var(--ink)\">Co\u00fbt moyen d'acquisition = Total investi / Nombre total d'actions achet\u00e9es</div>\n  <div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Toujours inf\u00e9rieur ou \u00e9gal \u00e0 la moyenne arithm\u00e9tique des prix d'achat \u2014 avantage math\u00e9matique intrins\u00e8que</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La m\u00e9canique anti-intuitive du DCA</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Exemple : vous investissez 100 \u20ac par mois. Mois 1 : prix 10 \u20ac \u2192 10 actions. Mois 2 : prix 5 \u20ac \u2192 20 actions. Mois 3 : prix 20 \u20ac \u2192 5 actions. Total : 300 \u20ac investis, 35 actions achet\u00e9es, co\u00fbt moyen = 8,57 \u20ac. La moyenne arithm\u00e9tique des prix \u00e9tait (10+5+20)/3 = 11,67 \u20ac. <strong style=\"color:var(--ink)\">Votre co\u00fbt moyen est inf\u00e9rieur \u00e0 la moyenne des prix</strong> \u2014 c'est l'avantage math\u00e9matique du DCA.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">DCA vs Lump Sum : le d\u00e9bat</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Les \u00e9tudes acad\u00e9miques montrent que l'investissement en une seule fois (Lump Sum) bat statistiquement le DCA dans ~65-70 % des cas sur des march\u00e9s haussiers \u00e0 long terme \u2014 simplement parce que les march\u00e9s montent plus souvent qu'ils ne baissent. Mais le DCA bat le Lump Sum dans les march\u00e9s baissiers ou volatils, et surtout il <strong style=\"color:var(--ink)\">r\u00e9duit le risque psychologique</strong> : l'investisseur qui \u00e9chelonne son investissement panique moins lors d'une correction.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0 28px\">\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">Avantages du DCA</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">\u00c9limine le timing</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Pas besoin de pr\u00e9dire les march\u00e9s</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Discipline automatique</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Investissement r\u00e9gulier sans d\u00e9cision</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">R\u00e9duction du risque psychologique</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Pas de 'tout-in' au mauvais moment</span></div>\n    </div>\n  </div>\n  <div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n    <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:10px\">Limites du DCA</div>\n    <div style=\"font-size:0.88rem;color:var(--ink2);line-height:1.7\">\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Sous-optimal en march\u00e9 haussier</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Le Lump Sum bat le DCA 65 % du temps</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Frais de courtage</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Multiplication des transactions</span></div>\n      <div style=\"margin-bottom:6px\"><strong style=\"color:var(--ink)\">Faux sentiment de s\u00e9curit\u00e9</strong><br><span style=\"color:var(--muted);font-size:0.8rem\">Ne prot\u00e8ge pas contre les march\u00e9s durablement baissiers</span></div>\n    </div>\n  </div>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n  <div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">\u00c0 retenir</div>\n  <p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\">Le DCA est la strat\u00e9gie id\u00e9ale pour l'investisseur qui n'a pas de capital \u00e0 investir en une fois ou qui veut \u00e9viter le risque de 'tout-in au mauvais moment'. Math\u00e9matiquement, le co\u00fbt moyen DCA est toujours inf\u00e9rieur ou \u00e9gal \u00e0 la moyenne des prix. Psychologiquement, il \u00e9limine le stress du timing de march\u00e9 \u2014 son vrai avantage pour la plupart des investisseurs.</p>\n</div>\n"
});


